@dataclass(slots=True)
class _ManagedQtWorkerJob:
    """Track detached Qt worker threads so they outlive closing widgets."""

    thread: QtCore.QThread
    worker: QtCore.QObject
    label: str


def _retain_top_level_window(window: QtWidgets.QWidget) -> QtWidgets.QWidget:
    """Hold a strong reference for top-level widgets created from helper APIs."""
    key = id(window)
    _TOP_LEVEL_WINDOW_REFERENCES[key] = window
    window.destroyed.connect(lambda *_args, _key=key: _TOP_LEVEL_WINDOW_REFERENCES.pop(_key, None))
    return window


def _safe_disconnect(signal: Any, slot: Callable[..., Any]) -> None:
    """Disconnect a Qt signal/slot pair when it is currently connected."""
    try:
        signal.disconnect(slot)
    except (RuntimeError, TypeError):
        pass


def _show_exception_warning(
    parent: QtWidgets.QWidget | None,
    title: str,
    friendly_text: str,
    exc: BaseException,
) -> None:
    """Show a friendly warning dialog with the raw exception in a secondary field."""
    box = QtWidgets.QMessageBox(parent)
    box.setIcon(QtWidgets.QMessageBox.Warning)
    box.setWindowTitle(title)
    box.setText(friendly_text)
    detail = str(exc).strip()
    if detail:
        box.setInformativeText(detail)
    box.setDetailedText(f"{type(exc).__name__}: {exc}")
    box.setStandardButtons(QtWidgets.QMessageBox.Ok)
    box.exec()


def _flush_deferred_deletions() -> None:
    """Force immediate destruction of Qt objects scheduled via deleteLater().

    Without this, deferred deletions accumulate until the event loop is
    idle — which in a busy GUI or a test loop may never happen.  Each
    undestroyed widget tree holds its full C++ object graph and any
    associated GPU resources (VTK render windows, CUDA contexts, etc.).
    """
    app = QtWidgets.QApplication.instance()
    if app is not None:
        app.sendPostedEvents(None, QtCore.QEvent.DeferredDelete)


def _detach_qobject_from_parent(obj: QtCore.QObject | None) -> None:
    """Unparent a QObject so widget destruction cannot reclaim it prematurely."""
    if obj is None:
        return
    try:
        if obj.parent() is not None:
            obj.setParent(None)
    except Exception:
        pass


def _retain_managed_worker_job(
    thread: QtCore.QThread,
    worker: QtCore.QObject,
    *,
    label: str,
) -> int:
    """Keep a detached worker job alive until its thread exits."""
    job_id = id(thread)
    _MANAGED_QT_WORKER_JOBS[job_id] = _ManagedQtWorkerJob(
        thread=thread,
        worker=worker,
        label=str(label),
    )
    thread.finished.connect(lambda _job_id=job_id: _release_managed_worker_job(_job_id))
    return job_id


def _release_managed_worker_job(job_id: int) -> None:
    """Release a retained worker job once the thread has fully stopped."""
    _MANAGED_QT_WORKER_JOBS.pop(int(job_id), None)


def _detach_managed_worker_job(
    thread: QtCore.QThread | None,
    worker: QtCore.QObject | None,
) -> None:
    """Ensure a worker job is no longer owned by a closing widget tree."""
    _detach_qobject_from_parent(thread)
    _detach_qobject_from_parent(worker)


def _request_worker_thread_shutdown(
    thread: QtCore.QThread | None,
    *,
    wait_ms: int = 0,
) -> bool:
    """Ask a worker thread to stop without assuming the worker cooperates."""
    if thread is None:
        return True
    try:
        thread.requestInterruption()
    except Exception:
        pass
    try:
        thread.quit()
    except Exception:
        pass
    if int(wait_ms) <= 0:
        try:
            return not bool(thread.isRunning())
        except Exception:
            return False
    try:
        return bool(thread.wait(int(wait_ms)))
    except Exception:
        return False

