def _default_output_families_config() -> dict[str, dict[str, Any]]:
    return scenario.default_output_families()


def _normalize_output_families_config(
    output_families: Mapping[str, Any] | None,
) -> dict[str, dict[str, Any]]:
    return scenario.normalize_output_family_configs(
        output_families,
        ignore_unknown=True,
    )


def _infer_legacy_service_bandwidth_mhz(
    output_families: Mapping[str, Mapping[str, Any]] | None,
) -> float:
    configs = _normalize_output_families_config(output_families)
    values: list[float] = []
    for family_name in ("prx_total_distribution", "prx_elevation_heatmap"):
        value = configs.get(family_name, {}).get("bandwidth_mhz")
        if value is None:
            continue
        try:
            value_float = float(value)
        except Exception:
            continue
        if np.isfinite(value_float) and value_float > 0.0:
            values.append(value_float)
    if not values:
        return float(_DEFAULT_SERVICE_BANDWIDTH_MHZ)
    if all(abs(value - values[0]) <= 1.0e-9 for value in values[1:]):
        return float(values[0])
    return float(_DEFAULT_SERVICE_BANDWIDTH_MHZ)


def _summarize_output_family_modes(output_families: Mapping[str, Mapping[str, Any]]) -> str:
    configs = _normalize_output_families_config(output_families)
    parts = [
        f"{_OUTPUT_FAMILY_LABELS.get(name, name)}={configs[name].get('mode', 'unknown')}"
        for name in _OUTPUT_FAMILY_ORDER
    ]
    return ", ".join(parts)


def _validate_output_families_config(
    output_families: Mapping[str, Mapping[str, Any]],
) -> tuple[bool, str]:
    return scenario.validate_output_family_configs(
        output_families,
        ignore_unknown=True,
    )


