def _legacy_overlap_spectrum_config(
    service: "ServiceConfig",
    antennas: "AntennasConfig | None",
) -> "SpectrumConfig":
    bandwidth_mhz = float(
        _DEFAULT_SERVICE_BANDWIDTH_MHZ
        if service.bandwidth_mhz is None
        else service.bandwidth_mhz
    )
    reference_frequency_mhz = float(
        antennas.frequency_mhz
        if antennas is not None and antennas.frequency_mhz is not None
        else 0.5 * (
            _DEFAULT_SPECTRUM_RAS_BAND_START_MHZ + _DEFAULT_SPECTRUM_RAS_BAND_STOP_MHZ
        )
    )
    half_bandwidth_mhz = 0.5 * float(bandwidth_mhz)
    return SpectrumConfig(
        service_band_start_mhz=float(reference_frequency_mhz - half_bandwidth_mhz),
        service_band_stop_mhz=float(reference_frequency_mhz + half_bandwidth_mhz),
        reuse_factor=1,
        disabled_channel_indices=None,
        ras_anchor_reuse_slot=0,
        multi_group_power_policy=str(_DEFAULT_SPECTRUM_POWER_POLICY),
        split_total_group_denominator_mode=str(_DEFAULT_SPECTRUM_SPLIT_DENOMINATOR_MODE),
        unwanted_emission_mask_preset=str(_DEFAULT_SPECTRUM_MASK_PRESET),
        custom_mask_points=None,
        spectral_integration_cutoff_basis=str(_DEFAULT_SPECTRUM_CUTOFF_BASIS),
        spectral_integration_cutoff_percent=float(_DEFAULT_SPECTRUM_CUTOFF_PERCENT),
        tx_reference_mode=str(_DEFAULT_SPECTRUM_TX_REFERENCE_MODE),
        tx_reference_point_count=int(_DEFAULT_SPECTRUM_TX_REFERENCE_POINT_COUNT),
    )


def _migrate_legacy_tx_custom_mask_points(
    custom_mask_points: Any,
    *,
    channel_bandwidth_mhz: float | None,
) -> list[list[float]] | None:
    if _is_gui_optional_scalar_missing(custom_mask_points):
        return None
    bandwidth_mhz = float(
        _DEFAULT_SERVICE_BANDWIDTH_MHZ
        if channel_bandwidth_mhz is None
        else channel_bandwidth_mhz
    )
    try:
        migrated = scenario._legacy_direct_epfd_mask_points_to_signed_centered(
            custom_mask_points,
            channel_bandwidth_mhz=bandwidth_mhz,
        )
    except Exception:
        return [
            [float(point[0]), float(point[1])]
            for point in list(custom_mask_points)
        ]
    return np.asarray(migrated, dtype=np.float64).tolist()


def _is_gui_optional_scalar_missing(value: Any) -> bool:
    """Return True when one optional GUI payload value is semantically blank."""
    if value is None:
        return True
    if isinstance(value, str):
        return value.strip() == ""
    return False


def _normalize_gui_int_list(values: Any) -> list[int]:
    """Normalize one GUI payload field into a flat integer list."""
    if _is_gui_optional_scalar_missing(values):
        return []
    if isinstance(values, np.ndarray):
        raw_values = np.asarray(values).reshape(-1).tolist()
    elif np.isscalar(values) and not isinstance(values, (str, bytes, bytearray)):
        raw_values = [values]
    else:
        raw_values = list(values)
    return [int(value) for value in raw_values]


def _migrate_legacy_channel_groups_cap_to_disabled_indices(
    spectrum_payload: Mapping[str, Any] | None,
    *,
    channel_bandwidth_mhz: float | None,
) -> list[int] | None:
    """Convert schema-v13 bottom-up cap semantics into explicit disabled channels."""
    if spectrum_payload is None:
        return None
    payload = dict(spectrum_payload)
    if not _is_gui_optional_scalar_missing(payload.get("disabled_channel_indices")):
        return _normalize_gui_int_list(payload.get("disabled_channel_indices"))
    if "channel_groups_per_cell_cap" not in payload:
        return None
    bandwidth_mhz = (
        None
        if channel_bandwidth_mhz is None
        else float(channel_bandwidth_mhz)
    )
    service_start = payload.get("service_band_start_mhz")
    service_stop = payload.get("service_band_stop_mhz")
    reuse_factor_raw = payload.get("reuse_factor", _DEFAULT_SPECTRUM_REUSE_FACTOR)
    if (
        bandwidth_mhz is None
        or _is_gui_optional_scalar_missing(service_start)
        or _is_gui_optional_scalar_missing(service_stop)
    ):
        return None
    service_bandwidth_total_mhz = float(service_stop) - float(service_start)
    if not np.isfinite(service_bandwidth_total_mhz) or service_bandwidth_total_mhz <= 0.0:
        return None
    full_channel_count = int(np.floor(service_bandwidth_total_mhz / float(bandwidth_mhz)))
    if full_channel_count < 1:
        return None
    reuse_factor = max(1, int(reuse_factor_raw or _DEFAULT_SPECTRUM_REUSE_FACTOR))
    max_groups_per_cell = max(1, int(full_channel_count // reuse_factor))
    groups_cap_raw = payload.get("channel_groups_per_cell_cap")
    groups_cap = (
        int(max_groups_per_cell)
        if _is_gui_optional_scalar_missing(groups_cap_raw)
        else max(1, int(groups_cap_raw))
    )
    groups_per_cell = max(1, min(int(groups_cap), int(max_groups_per_cell)))
    enabled_channel_indices = {
        int(slot_id + reuse_factor * group_index)
        for slot_id in range(int(reuse_factor))
        for group_index in range(int(groups_per_cell))
        if int(slot_id + reuse_factor * group_index) < int(full_channel_count)
    }
    disabled_channel_indices = [
        int(channel_index)
        for channel_index in range(int(full_channel_count))
        if int(channel_index) not in enabled_channel_indices
    ]
    return disabled_channel_indices or None


def _merge_legacy_receiver_fields_into_ras_payload(
    *,
    ras_payload: Mapping[str, Any] | None,
    spectrum_payload: Mapping[str, Any] | None,
) -> dict[str, Any] | None:
    payload = {} if ras_payload is None else dict(ras_payload)
    spectrum_use = {} if spectrum_payload is None else dict(spectrum_payload)
    migrated_any = ras_payload is not None
    legacy_field_map = {
        "receiver_band_start_mhz": "ras_receiver_band_start_mhz",
        "receiver_band_stop_mhz": "ras_receiver_band_stop_mhz",
        "ras_reference_mode": "ras_reference_mode",
        "ras_reference_point_count": "ras_reference_point_count",
    }
    for target_key, legacy_key in legacy_field_map.items():
        if (
            _is_gui_optional_scalar_missing(payload.get(target_key))
            and not _is_gui_optional_scalar_missing(spectrum_use.get(legacy_key))
        ):
            payload[target_key] = spectrum_use.get(legacy_key)
            migrated_any = True
    if _is_gui_optional_scalar_missing(payload.get("receiver_response_mode")):
        payload["receiver_response_mode"] = _DEFAULT_RAS_RECEIVER_RESPONSE_MODE
        migrated_any = migrated_any or any(
            not _is_gui_optional_scalar_missing(payload.get(key))
            for key in (
                "receiver_band_start_mhz",
                "receiver_band_stop_mhz",
                "ras_reference_mode",
                "ras_reference_point_count",
            )
        )
    if _is_gui_optional_scalar_missing(payload.get("receiver_custom_mask_points")):
        payload["receiver_custom_mask_points"] = None
    return payload if migrated_any else None


