class SatelliteAntennasConfig:
    """TX-side satellite antenna controls (extracted from AntennasConfig, no RAS)."""

    frequency_mhz: float | None = None
    pattern_wavelength_cm: float | None = None
    derive_pattern_wavelength_from_frequency: bool = False
    antenna_model: str | None = None
    rec12: AntennaRec12Config = field(default_factory=AntennaRec12Config)
    rec14: AntennaRec14Config = field(default_factory=AntennaRec14Config)
    m2101: AntennaM2101Config = field(default_factory=AntennaM2101Config)
    isotropic: AntennaIsotropicConfig = field(default_factory=AntennaIsotropicConfig)
    # Optional user-supplied TX antenna pattern LUT (schema v1).
    # Runtime wiring lands in Phase 4; for Stage 3 the field round-trips
    # through project JSON. Old projects without the field load as None.
    custom_pattern: "CustomAntennaPattern | None" = None

    def to_json_dict(self) -> dict[str, Any]:
        return {
            "frequency_mhz": None if self.frequency_mhz is None else float(self.frequency_mhz),
            "pattern_wavelength_cm": (
                None if self.pattern_wavelength_cm is None else float(self.pattern_wavelength_cm)
            ),
            "derive_pattern_wavelength_from_frequency": bool(
                self.derive_pattern_wavelength_from_frequency
            ),
            "antenna_model": None if self.antenna_model is None else str(self.antenna_model),
            "rec12": self.rec12.to_json_dict(),
            "rec14": self.rec14.to_json_dict(),
            "m2101": self.m2101.to_json_dict(),
            "isotropic": self.isotropic.to_json_dict(),
            "custom_pattern": (
                None if self.custom_pattern is None else self.custom_pattern.to_json_dict()
            ),
        }

    @classmethod
    def from_json_dict(cls, payload: dict[str, Any]) -> "SatelliteAntennasConfig":
        return cls(
            frequency_mhz=(
                None if payload.get("frequency_mhz") is None else float(payload["frequency_mhz"])
            ),
            pattern_wavelength_cm=(
                None
                if payload.get("pattern_wavelength_cm") is None
                else float(payload["pattern_wavelength_cm"])
            ),
            derive_pattern_wavelength_from_frequency=bool(
                payload.get("derive_pattern_wavelength_from_frequency", False)
            ),
            antenna_model=(
                None if payload.get("antenna_model") is None else str(payload["antenna_model"])
            ),
            rec12=AntennaRec12Config.from_json_dict(payload.get("rec12") or {}),
            rec14=AntennaRec14Config.from_json_dict(payload.get("rec14") or {}),
            m2101=(
                AntennaM2101Config.from_json_dict(payload["m2101"])
                if "m2101" in payload and payload["m2101"] is not None
                else AntennaM2101Config()
            ),
            isotropic=AntennaIsotropicConfig.from_json_dict(payload.get("isotropic")),
            custom_pattern=_parse_custom_pattern_field(payload.get("custom_pattern")),
        )

    @classmethod
    def from_antennas_config(cls, cfg: "AntennasConfig") -> "SatelliteAntennasConfig":
        """Extract the TX-side fields from a legacy AntennasConfig."""
        return cls(
            frequency_mhz=cfg.frequency_mhz,
            pattern_wavelength_cm=cfg.pattern_wavelength_cm,
            derive_pattern_wavelength_from_frequency=cfg.derive_pattern_wavelength_from_frequency,
            antenna_model=cfg.antenna_model,
            rec12=AntennaRec12Config.from_json_dict(cfg.rec12.to_json_dict()),
            rec14=AntennaRec14Config.from_json_dict(cfg.rec14.to_json_dict()),
            m2101=AntennaM2101Config.from_json_dict(cfg.m2101.to_json_dict()),
            isotropic=AntennaIsotropicConfig.from_json_dict(cfg.isotropic.to_json_dict()),
        )

    def to_antennas_config(self, ras: RasAntennaConfig | None = None) -> "AntennasConfig":
        """Reconstruct a legacy AntennasConfig for backwards compatibility.

        Forwards ``custom_pattern`` so Custom 1-D / 2-D satellite-antenna
        configs survive the round-trip into the legacy class that the scenario
        pipeline still consumes.
        """
        return AntennasConfig(
            frequency_mhz=self.frequency_mhz,
            pattern_wavelength_cm=self.pattern_wavelength_cm,
            derive_pattern_wavelength_from_frequency=self.derive_pattern_wavelength_from_frequency,
            antenna_model=self.antenna_model,
            rec12=AntennaRec12Config.from_json_dict(self.rec12.to_json_dict()),
            rec14=AntennaRec14Config.from_json_dict(self.rec14.to_json_dict()),
            m2101=AntennaM2101Config.from_json_dict(self.m2101.to_json_dict()),
            isotropic=AntennaIsotropicConfig.from_json_dict(self.isotropic.to_json_dict()),
            ras=RasAntennaConfig.from_json_dict((ras or RasAntennaConfig()).to_json_dict()),
            custom_pattern=self.custom_pattern,
        )


