def _pattern_wavelength_cm_from_frequency_mhz(frequency_mhz: float) -> float:
    return antenna.pattern_wavelength_cm_from_frequency_mhz(frequency_mhz)


def _has_any_ras_station_value(config: RasStationConfig | None) -> bool:
    if config is None:
        return False
    return any(
        value is not None
        for value in (
            config.longitude_deg,
            config.latitude_deg,
            config.elevation_m,
            config.receiver_band_start_mhz,
            config.receiver_band_stop_mhz,
            config.receiver_response_mode,
            config.receiver_custom_mask_points,
            config.ras_reference_mode,
            config.ras_reference_point_count,
        )
    )


def _has_any_spectrum_value(config: SpectrumConfig | None) -> bool:
    if config is None:
        return False
    return any(
        value is not None
        for value in (
            config.service_band_start_mhz,
            config.service_band_stop_mhz,
            config.reuse_factor,
            config.ras_anchor_reuse_slot,
            config.multi_group_power_policy,
            config.split_total_group_denominator_mode,
            config.unwanted_emission_mask_preset,
            config.custom_mask_points,
            config.spectral_integration_cutoff_basis,
            config.spectral_integration_cutoff_percent,
            config.tx_reference_mode,
            config.tx_reference_point_count,
        )
    ) or bool(config.disabled_channel_indices)


def _has_complete_ras_station_config(config: RasStationConfig | None) -> bool:
    if config is None:
        return False
    return all(value is not None for value in (config.longitude_deg, config.latitude_deg, config.elevation_m))


def _has_any_antenna_value(config: AntennasConfig | SatelliteAntennasConfig | None) -> bool:
    if config is None:
        return False
    if config.frequency_mhz is not None or config.pattern_wavelength_cm is not None:
        return True
    if config.antenna_model is not None:
        return True
    rec12 = config.rec12
    if any(value is not None for value in (rec12.gm_dbi, rec12.ln_db, rec12.z)):
        return True
    rec14 = config.rec14
    if any(
        value is not None
        for value in (
            rec14.lt_m,
            rec14.lr_m,
            rec14.l,
            rec14.slr_db,
            rec14.far_sidelobe_start_deg,
            rec14.far_sidelobe_level_dbi,
        )
    ):
        return True
    ras = config.ras
    if any(
        value is not None
        for value in (
            ras.antenna_diameter_m,
            ras.operational_elevation_min_deg,
            ras.operational_elevation_max_deg,
            ras.target_pfd_dbw_m2_mhz,
        )
    ):
        return True
    return getattr(ras, "custom_pattern", None) is not None


def _has_valid_ras_antenna_config(config: AntennasConfig | RasAntennaConfig | None) -> bool:
    if config is None:
        return False
    ras = config.ras if isinstance(config, AntennasConfig) else config
    if (
        ras.operational_elevation_min_deg is None
        or ras.operational_elevation_max_deg is None
    ):
        return False
    elev_ok = (
        0.0
        <= float(ras.operational_elevation_min_deg)
        < float(ras.operational_elevation_max_deg)
        <= 90.0
    )
    if not elev_ok:
        return False
    # A user-supplied RAS pattern replaces the RA.1631
    # diameter+wavelength parameterisation. Both 1-D axisymmetric
    # (``kind=1d_axisymmetric``) and 2-D (``kind=2d``, either
    # ``theta_phi`` or ``az_el`` grid_mode) are accepted — the main
    # power kernel derives the φ rotation around the RAS boresight
    # so Custom-2D patterns are evaluated with both θ and φ.
    custom_pat = getattr(ras, "custom_pattern", None)
    if custom_pat is not None:
        return getattr(custom_pat, "kind", None) in (_CA_KIND_1D, _CA_KIND_2D)
    # Legacy RA.1631 path: needs a positive diameter.
    if ras.antenna_diameter_m is None:
        return False
    return float(ras.antenna_diameter_m) > 0.0


def _has_ras_pattern_for_preview(config: AntennasConfig | RasAntennaConfig | None) -> bool:
    """Check whether the RAS antenna has enough info to preview the
    pattern — does NOT require operational elevation angles (those
    drive the sky-cell scan, not the gain shape)."""
    if config is None:
        return False
    ras = config.ras if isinstance(config, AntennasConfig) else config
    custom_pat = getattr(ras, "custom_pattern", None)
    if custom_pat is not None:
        return getattr(custom_pat, "kind", None) in (_CA_KIND_1D, _CA_KIND_2D)
    if ras.antenna_diameter_m is None:
        return False
    return float(ras.antenna_diameter_m) > 0.0


def _state_target_pfd_dbw_m2_mhz(state: "ScepterProjectState") -> float | None:
    s0 = state.active_system()
    try:
        power_input = _normalize_service_config_power_input(s0.service)
    except Exception:
        power_input = None
    if power_input is not None and power_input.get("target_pfd_dbw_m2_mhz") is not None:
        return float(power_input["target_pfd_dbw_m2_mhz"])
    if s0.service.target_pfd_dbw_m2_mhz is not None:
        return float(s0.service.target_pfd_dbw_m2_mhz)
    if state.ras_antenna.target_pfd_dbw_m2_mhz is not None:
        return float(state.ras_antenna.target_pfd_dbw_m2_mhz)
    return None


def _service_power_quantity_label(quantity: str) -> str:
    return {
        "target_pfd": "Target PFD",
        "satellite_ptx": "Satellite Ptx",
        "satellite_eirp": "Satellite EIRP",
    }[str(quantity)]


def _service_power_basis_label(basis: str) -> str:
    return {"per_mhz": "per MHz", "per_channel": "per channel"}[str(basis)]


def _service_power_value_unit(quantity: str, basis: str) -> str:
    return {
        ("target_pfd", "per_mhz"): "dBW/m^2/MHz",
        ("target_pfd", "per_channel"): "dBW/m^2",
        ("satellite_ptx", "per_mhz"): "dBW/MHz",
        ("satellite_ptx", "per_channel"): "dBW",
        ("satellite_eirp", "per_mhz"): "dBW/MHz",
        ("satellite_eirp", "per_channel"): "dBW",
    }[(str(quantity), str(basis))]


def _service_power_help_summary(quantity: str, basis: str) -> str:
    quantity_name = _service_power_quantity_label(quantity)
    if str(quantity) == "target_pfd":
        basis_text = (
            "Reference-band target ground PFD entered per MHz."
            if str(basis) == "per_mhz"
            else "Integrated target ground PFD entered over the whole study channel."
        )
        return (
            f"{quantity_name} defined as {basis_text} "
            f"Units: {_service_power_value_unit(quantity, basis)}."
        )
    quantity_text = (
        "spectral-density transmit quantity"
        if str(basis) == "per_mhz"
        else "channel-total transmit quantity"
    )
    return (
        f"{quantity_name} entered as a {quantity_text}. "
        f"Units: {_service_power_value_unit(quantity, basis)}."
    )


def _service_power_help_details_html(quantity: str, basis: str) -> str:
    quantity_name = _service_power_quantity_label(quantity)
    basis_name = _service_power_basis_label(basis)
    unit_text = _service_power_value_unit(quantity, basis)
    if str(quantity) == "target_pfd":
        default_text = (
            "Use this when the service definition is expressed as a target ground PFD at the served point."
        )
        interaction_text = (
            "Changing the active quantity or basis switches the visible editor and updates the linked equivalent value using a single 10*log10(B) conversion through the channel bandwidth."
        )
    elif str(quantity) == "satellite_ptx":
        default_text = (
            "Use this when the service is controlled directly by transmit power rather than a target ground PFD."
        )
        interaction_text = (
            "Per-MHz inputs are spectral densities in dBW/MHz, while per-channel inputs are channel totals in dBW."
        )
    else:
        default_text = (
            "Use this when the service is controlled directly by boresight EIRP rather than a target ground PFD."
        )
        interaction_text = (
            "Per-MHz inputs are spectral densities in dBW/MHz, while per-channel inputs are channel totals in dBW."
        )
    return (
        f"<p style='margin:0 0 6px 0;'><b>Active definition.</b> "
        f"{quantity_name} {_service_power_basis_label(basis)} "
        f"({unit_text}).</p>"
        f"<p style='margin:0 0 6px 0;'><b>Safe default.</b> {default_text}</p>"
        f"<p style='margin:0 0 6px 0;'><b>Interactions.</b> {interaction_text}</p>"
        f"<p style='margin:0;'><b>Units.</b> This control is currently using "
        f"{basis_name} units: {unit_text}.</p>"
    )


def _service_cell_activity_mode_label(mode: str) -> str:
    return {
        "whole_cell": "whole cell",
        "per_channel": "per channel",
    }[str(mode)]


def _normalize_service_config_power_input(config: "ServiceConfig") -> dict[str, Any]:
    return scenario.normalize_direct_epfd_power_input(
        bandwidth_mhz=float(
            _DEFAULT_SERVICE_BANDWIDTH_MHZ
            if config.bandwidth_mhz is None
            else config.bandwidth_mhz
        ),
        power_input_quantity=(
            _DEFAULT_SERVICE_POWER_INPUT_QUANTITY
            if config.power_input_quantity in {None, ""}
            else str(config.power_input_quantity)
        ),
        power_input_basis=(
            _DEFAULT_SERVICE_POWER_INPUT_BASIS
            if config.power_input_basis in {None, ""}
            else str(config.power_input_basis)
        ),
        pfd0_dbw_m2_mhz=None,
        target_pfd_dbw_m2_mhz=config.target_pfd_dbw_m2_mhz,
        target_pfd_dbw_m2_channel=config.target_pfd_dbw_m2_channel,
        satellite_ptx_dbw_mhz=config.satellite_ptx_dbw_mhz,
        satellite_ptx_dbw_channel=config.satellite_ptx_dbw_channel,
        satellite_eirp_dbw_mhz=config.satellite_eirp_dbw_mhz,
        satellite_eirp_dbw_channel=config.satellite_eirp_dbw_channel,
        power_variation_mode=config.power_variation_mode,
        power_range_min_db=config.power_range_min_db,
        power_range_max_db=config.power_range_max_db,
    )


def _require_service_power_input(state: "ScepterProjectState") -> dict[str, Any]:
    try:
        return _normalize_service_config_power_input(state.active_system().service)
    except ValueError as exc:
        raise ValueError(
            "A finite service power-definition value is required before building a run request."
        ) from exc


def _require_finite_service_target_pfd_dbw_m2_mhz(state: "ScepterProjectState") -> float:
    power_input = _require_service_power_input(state)
    target_pfd = power_input.get("target_pfd_dbw_m2_mhz")
    if target_pfd is None or not np.isfinite(float(target_pfd)):
        raise ValueError("A finite target PFD is not available for this service configuration.")
    return float(target_pfd)


def _service_power_input_summary(
    power_input: Mapping[str, Any],
    *,
    uemr_mode: bool = False,
) -> str:
    # UEMR runs bypass the channel-bandwidth concept entirely — the kernel
    # uses the full service-band width — so omit the "(bandwidth X MHz)"
    # suffix to avoid implying a separate knob the user should tune.
    core = (
        f"{_service_power_quantity_label(str(power_input['power_input_quantity']))} "
        f"{_service_power_basis_label(str(power_input['power_input_basis']))} "
        f"{float(power_input['active_value']):.2f} {str(power_input['active_value_unit'])}"
    )
    if uemr_mode:
        return core
    return f"{core} (bandwidth {float(power_input['bandwidth_mhz']):.3f} MHz)"


def _has_valid_service_config(
    config: "ServiceConfig",
    *,
    uemr_mode: bool = False,
) -> bool:
    # In UEMR mode the beam library is bypassed entirely, so Nco, Nbeam,
    # selection strategy, and cell-activity settings are meaningless. Only
    # a valid power input (EIRP/Ptx per MHz) is required — the channel
    # bandwidth auto-derives from the service band on the Spectrum tab.
    if not uemr_mode:
        if config.nco is None or int(config.nco) <= 0:
            return False
        if config.nbeam is None or int(config.nbeam) <= 0:
            return False
        if str(config.selection_strategy or "") not in {value for _, value in _SELECTION_STRATEGY_OPTIONS}:
            return False
        if config.cell_activity_factor is None:
            return False
        if not (0.0 <= float(config.cell_activity_factor) <= 1.0):
            return False
        try:
            scenario._normalize_direct_epfd_cell_activity_mode(config.cell_activity_mode)
        except Exception:
            return False
        if config.bandwidth_mhz is None:
            return False
        try:
            bandwidth_mhz = float(config.bandwidth_mhz)
        except Exception:
            return False
        if not np.isfinite(bandwidth_mhz) or bandwidth_mhz <= 0.0:
            return False
    else:
        # UEMR: the power-quantity combo only offers Ptx and EIRP (Target
        # PFD has no meaning without a directive beam), so require one
        # of those two to be explicitly set. The default target_pfd fallback
        # is intentionally ignored — otherwise Service would read as "ready"
        # before the user had entered anything.
        quantity = str(config.power_input_quantity or "satellite_ptx").lower()
        if quantity not in {"satellite_ptx", "satellite_eirp"}:
            return False
        value = (
            config.satellite_ptx_dbw_mhz
            if quantity == "satellite_ptx"
            else config.satellite_eirp_dbw_mhz
        )
        try:
            return value is not None and np.isfinite(float(value))
        except (TypeError, ValueError):
            return False
    try:
        _normalize_service_config_power_input(config)
    except Exception:
        return False
    return True


def _system_is_uemr(sys_cfg: "ScepterSystemState") -> bool:
    """Return True when this system is configured for UEMR isotropic mode."""
    ant = getattr(sys_cfg, "satellite_antennas", None)
    if ant is None:
        return False
    if str(getattr(ant, "antenna_model", "") or "") != _ANTENNA_MODEL_ISOTROPIC:
        return False
    iso = getattr(ant, "isotropic", None)
    return bool(iso is not None and getattr(iso, "uemr_mode", False))


def _normalize_spectrum_config(
    service: "ServiceConfig",
    spectrum: "SpectrumConfig",
    ras_station: "RasStationConfig | None",
    *,
    active_cell_reuse_slot_ids: Any | None = None,
    active_cell_count: int | None = None,
) -> dict[str, Any]:
    if service.bandwidth_mhz is None:
        raise ValueError("Set Channel bandwidth [MHz] on Service & Demand first.")
    bandwidth_mhz = float(service.bandwidth_mhz)
    combined_payload = dict(spectrum.to_json_dict())
    ras_cfg = ras_station
    if ras_cfg is not None:
        combined_payload.update(
            {
                "ras_receiver_band_start_mhz": ras_cfg.receiver_band_start_mhz,
                "ras_receiver_band_stop_mhz": ras_cfg.receiver_band_stop_mhz,
                "receiver_response_mode": ras_cfg.receiver_response_mode,
                "receiver_custom_mask_points": ras_cfg.receiver_custom_mask_points,
                "ras_reference_mode": ras_cfg.ras_reference_mode,
                "ras_reference_point_count": ras_cfg.ras_reference_point_count,
            }
        )
    plan = scenario.normalize_direct_epfd_spectrum_plan(
        spectrum_plan=combined_payload,
        channel_bandwidth_mhz=float(bandwidth_mhz),
        active_cell_count=active_cell_count,
        active_cell_reuse_slot_ids=active_cell_reuse_slot_ids,
    ) or {}
    return dict(plan) if plan else {}


def _partial_spectrum_band_plan(
    service: "ServiceConfig",
    spectrum: "SpectrumConfig",
) -> dict[str, Any] | None:
    """Return reuse/highlighting data that only depends on the service band plan."""
    if service.bandwidth_mhz is None:
        return None
    if spectrum.service_band_start_mhz is None or spectrum.service_band_stop_mhz is None:
        return None
    channel_bandwidth_mhz = float(service.bandwidth_mhz)
    service_start_mhz = float(spectrum.service_band_start_mhz)
    service_stop_mhz = float(spectrum.service_band_stop_mhz)
    if not np.isfinite(channel_bandwidth_mhz) or channel_bandwidth_mhz <= 0.0:
        return None
    if not (
        np.isfinite(service_start_mhz)
        and np.isfinite(service_stop_mhz)
        and service_stop_mhz > service_start_mhz
    ):
        return None
    service_bandwidth_total_mhz = float(service_stop_mhz - service_start_mhz)
    full_channel_count = int(np.floor(service_bandwidth_total_mhz / channel_bandwidth_mhz))
    if full_channel_count < 1:
        return None
    leftover_spectrum_mhz = float(
        service_bandwidth_total_mhz - full_channel_count * channel_bandwidth_mhz
    )
    reuse_factor = (
        max(1, int(spectrum.reuse_factor))
        if spectrum.reuse_factor is not None
        else 1
    )
    max_groups_per_cell = max(1, int(full_channel_count // reuse_factor))
    disabled_channel_indices = _sanitize_disabled_channel_indices(
        spectrum.disabled_channel_indices,
        full_channel_count=int(full_channel_count),
    )
    disabled_set = set(disabled_channel_indices or [])
    enabled_channel_indices = [
        int(channel_index)
        for channel_index in range(int(full_channel_count))
        if int(channel_index) not in disabled_set
    ]
    enabled_by_slot: list[list[int]] = [[] for _ in range(int(reuse_factor))]
    for channel_index in enabled_channel_indices:
        enabled_by_slot[int(channel_index % reuse_factor)].append(int(channel_index))
    groups_per_cell = max(
        1,
        max((len(channel_indices) for channel_indices in enabled_by_slot), default=0),
    )
    zero_leftover_reuse_factors = tuple(
        int(candidate)
        for candidate in _SPECTRUM_REUSE_FACTOR_OPTIONS
        if leftover_spectrum_mhz <= 1.0e-9 and full_channel_count % int(candidate) == 0
    )
    return {
        "service_band_start_mhz": float(service_start_mhz),
        "service_band_stop_mhz": float(service_stop_mhz),
        "service_bandwidth_total_mhz": float(service_bandwidth_total_mhz),
        "channel_bandwidth_mhz": float(channel_bandwidth_mhz),
        "full_channel_count": int(full_channel_count),
        "leftover_spectrum_mhz": float(leftover_spectrum_mhz),
        "leftover_channel_fraction": float(leftover_spectrum_mhz / channel_bandwidth_mhz),
        "reuse_factor": int(reuse_factor),
        "zero_leftover_reuse_factors": tuple(zero_leftover_reuse_factors),
        "channel_groups_per_cell": int(groups_per_cell),
        "max_groups_per_cell": int(max_groups_per_cell),
        "enabled_channel_indices": tuple(int(value) for value in enabled_channel_indices),
        "disabled_channel_indices": tuple(int(value) for value in (disabled_channel_indices or [])),
        "enabled_channel_count": int(len(enabled_channel_indices)),
        "multi_group_power_policy": str(
            spectrum.multi_group_power_policy or _DEFAULT_SPECTRUM_POWER_POLICY
        ),
        "split_total_group_denominator_mode": str(
            spectrum.split_total_group_denominator_mode
            or _DEFAULT_SPECTRUM_SPLIT_DENOMINATOR_MODE
        ),
    }


def _spectrum_summary_text(plan: Mapping[str, Any]) -> str:
    full_channels = int(plan.get("full_channel_count", 0))
    reuse_factor = int(plan.get("reuse_factor", 1))
    groups_per_cell = int(plan.get("channel_groups_per_cell", 1))
    max_groups_per_cell = int(plan.get("max_groups_per_cell", groups_per_cell))
    enabled_channel_count = int(plan.get("enabled_channel_count", full_channels))
    power_policy = str(plan.get("multi_group_power_policy", _DEFAULT_SPECTRUM_POWER_POLICY))
    split_mode = str(
        plan.get(
            "split_total_group_denominator_mode",
            _DEFAULT_SPECTRUM_SPLIT_DENOMINATOR_MODE,
        )
    )
    leftover_mhz = float(plan.get("leftover_spectrum_mhz", 0.0))
    leftover_channels = float(plan.get("leftover_channel_fraction", 0.0))
    zero_leftover = tuple(int(value) for value in plan.get("zero_leftover_reuse_factors", ()))
    zero_leftover_text = (
        ", ".join(f"F{value}" for value in zero_leftover)
        if zero_leftover
        else "none"
    )
    power_policy_text = {
        "repeat_per_group": "configured target/power per active channel",
        "split_total_cell_power": "one cell-total target/power split across channels",
    }.get(power_policy, str(power_policy))
    split_mode_text = {
        "configured_groups": "configured channels",
        "active_groups": "active channels",
    }.get(split_mode, str(split_mode))
    return (
        f"{enabled_channel_count}/{full_channels} channels enabled | cluster={reuse_factor} | "
        f"enabled groups/cell up to {groups_per_cell}/{max_groups_per_cell} | "
        f"power={power_policy_text}/{split_mode_text} | "
        f"leftover={leftover_mhz:.3f} MHz ({leftover_channels:.2f} channels) | "
        f"exact-fit reuse: {zero_leftover_text}"
    )


def _has_valid_spectrum_config(
    service: "ServiceConfig",
    spectrum: "SpectrumConfig",
    ras_station: "RasStationConfig | None",
) -> bool:
    try:
        _normalize_spectrum_config(service, spectrum, ras_station)
    except Exception:
        return False
    return True


def _validate_ras_receiver_band(
    config: "RasStationConfig | None",
) -> tuple[bool, str]:
    """Validate only the receiver band + reference-frequency settings.

    Gates the Preview/Edit Receiver Response button so the custom-mask editor
    can be opened before any points exist (the editor self-provides a default).
    """
    if config is None:
        return False, "Set the RAS receiver band first."
    start_mhz = config.receiver_band_start_mhz
    stop_mhz = config.receiver_band_stop_mhz
    if start_mhz is None or stop_mhz is None:
        return False, "Set the RAS receiver band start and stop."
    start_value = float(start_mhz)
    stop_value = float(stop_mhz)
    if not np.isfinite(start_value) or not np.isfinite(stop_value) or stop_value <= start_value:
        return False, "RAS receiver band must satisfy stop > start with finite MHz values."
    try:
        scenario._resolve_direct_epfd_receiver_response_mode(config.receiver_response_mode)
    except Exception as exc:
        return False, str(exc)
    try:
        scenario._resolve_direct_epfd_reference_frequencies_mhz(
            start_mhz=start_value,
            stop_mhz=stop_value,
            mode=str(config.ras_reference_mode or _DEFAULT_SPECTRUM_RAS_REFERENCE_MODE),
            point_count=int(config.ras_reference_point_count or 1),
        )
    except Exception as exc:
        return False, str(exc)
    return True, ""


def _validate_ras_receiver_config(
    config: "RasStationConfig | None",
) -> tuple[bool, str]:
    """Validate the receiver-side spectral controls shown on the RAS tab."""
    band_ok, band_msg = _validate_ras_receiver_band(config)
    if not band_ok:
        return band_ok, band_msg
    assert config is not None
    start_value = float(config.receiver_band_start_mhz)
    stop_value = float(config.receiver_band_stop_mhz)
    response_mode = scenario._resolve_direct_epfd_receiver_response_mode(
        config.receiver_response_mode
    )
    if response_mode == "custom":
        mask_pts = config.receiver_custom_mask_points
        if mask_pts is None or (hasattr(mask_pts, "__len__") and len(mask_pts) < 2):
            return False, "Custom receiver response mask requires at least 2 points."
        try:
            scenario._resolve_direct_epfd_receiver_response_points_mhz(
                response_mode="custom",
                receiver_bandwidth_mhz=float(stop_value - start_value),
                custom_mask_points=mask_pts,
            )
        except Exception as exc:
            return False, str(exc)
    return True, ""


def _with_loaded_ras_receiver_defaults(
    config: "RasStationConfig | None",
) -> "RasStationConfig | None":
    """Fill missing receiver-side defaults for preconfigured RAS station loads."""
    if config is None:
        return None
    if all(
        value is None
        for value in (
            config.receiver_band_start_mhz,
            config.receiver_band_stop_mhz,
            config.receiver_response_mode,
            config.ras_reference_mode,
        )
    ) and config.receiver_custom_mask_points in (None, []):
        if all(
            value is None
            for value in (
                config.longitude_deg,
                config.latitude_deg,
                config.elevation_m,
            )
        ):
            return config
    defaults = _default_ras_station_config()
    return replace(
        config,
        receiver_band_start_mhz=(
            defaults.receiver_band_start_mhz
            if config.receiver_band_start_mhz is None
            else config.receiver_band_start_mhz
        ),
        receiver_band_stop_mhz=(
            defaults.receiver_band_stop_mhz
            if config.receiver_band_stop_mhz is None
            else config.receiver_band_stop_mhz
        ),
        receiver_response_mode=(
            defaults.receiver_response_mode
            if config.receiver_response_mode in {None, ""}
            else config.receiver_response_mode
        ),
        ras_reference_mode=(
            defaults.ras_reference_mode
            if config.ras_reference_mode in {None, ""}
            else config.ras_reference_mode
        ),
        ras_reference_point_count=(
            defaults.ras_reference_point_count
            if config.ras_reference_point_count in {None, 0}
            else config.ras_reference_point_count
        ),
    )


_WORKFLOW_STATUS_ORDER: tuple[str, ...] = (
    "RAS Station",
    "Satellite System Mode",
    "Satellite Orbitals",
    "Satellite Antennas",
    "Service & Demand",
    "Spectrum & Reuse",
    "Coverage & Contours",
    "Coverage & Boresight",
    "Review & Run",
)


def _workflow_status_payload(
    *,
    ready: bool,
    kind: str,
    title: str,
    message: str,
    action: str,
    review_pending: bool = False,
) -> dict[str, Any]:
    """Return a serializable workflow-status payload."""
    return {
        "ready": bool(ready),
        "kind": str(kind),
        "title": str(title),
        "message": str(message),
        "action": str(action),
        "review_pending": bool(review_pending),
    }


def _compute_workflow_status_payloads(
    state: "ScepterProjectState",
    *,
    contour_is_current: bool,
    effective_cell_km: float | None,
    hexgrid_is_current: bool,
    hexgrid_status_message: str,
    run_ready: bool,
    run_message: str,
    run_in_progress: bool,
    review_run_state: str | None,
    spectrum_explicitly_configured: bool,
    sat_sys_mode_visited: bool = False,
) -> dict[str, dict[str, Any]]:
    """Compute serializable workflow status payloads without touching widgets."""
    all_systems = state.systems or [state.active_system()]
    n_systems = len(all_systems)
    any_uemr = any(_system_is_uemr(s) for s in all_systems)
    receiver_ready, receiver_message = _validate_ras_receiver_config(state.ras_station)
    ras_ready = (
        _has_complete_ras_station_config(state.ras_station)
        and _has_valid_ras_antenna_config(state.ras_antenna)
        and receiver_ready
    )
    # UEMR derives wavelength from the RAS antenna frequency — validate
    # it is set and positive so the run builder won't crash.
    if any_uemr and ras_ready:
        _ras_freq = getattr(state.ras_antenna, "frequency_mhz", None)
        if _ras_freq is None or float(_ras_freq) <= 0:
            ras_ready = False

    # --- Check each system for orbitals, antenna, service, spectrum ---
    orbitals_ready = True
    orbitals_issues: list[str] = []
    sat_ant_ready = True
    sat_ant_issues: list[str] = []
    service_ready = True
    service_issues: list[str] = []
    spectrum_ready = spectrum_explicitly_configured
    spectrum_issues: list[str] = []
    spectrum_summary = ""
    power_summary: str | None = None

    for sys_idx, sys_cfg in enumerate(all_systems):
        label = sys_cfg.system_name or f"System {sys_idx + 1}"
        # Orbitals
        if len(sys_cfg.belts) < 1:
            orbitals_ready = False
            orbitals_issues.append(f"{label}: no belts defined")
        # Antenna
        if not _has_valid_satellite_antenna_config(sys_cfg.satellite_antennas):
            sat_ant_ready = False
            sat_ant_issues.append(f"{label}: antenna incomplete")
        # Service
        if not _has_valid_service_config(sys_cfg.service, uemr_mode=_system_is_uemr(sys_cfg)):
            service_ready = False
            service_issues.append(f"{label}: service incomplete")
        # Spectrum — UEMR uses a simplified "service band + mask preset"
        # check (no cell-reuse machinery); directive systems go through
        # the full cell-reuse normalize. ``spectrum_explicitly_configured``
        # is required so defaults-from-state don't silently count as
        # user-provided input — the user must actually touch the widgets.
        if _system_is_uemr(sys_cfg):
            _sp = sys_cfg.spectrum
            _band_ok = (
                spectrum_explicitly_configured
                and _sp.service_band_start_mhz is not None
                and _sp.service_band_stop_mhz is not None
                and float(_sp.service_band_stop_mhz) > float(_sp.service_band_start_mhz)
            )
            _mask_ok = (
                spectrum_explicitly_configured
                and bool(_sp.unwanted_emission_mask_preset)
            )
            if _band_ok and _mask_ok:
                spectrum_ready = True
            else:
                spectrum_ready = False
                missing = []
                if not _band_ok:
                    missing.append("service band (start/stop, stop > start)")
                if not _mask_ok:
                    missing.append("transmit unwanted-emission mask preset")
                spectrum_issues.append(f"{label}: UEMR needs {', '.join(missing)}")
        elif spectrum_explicitly_configured:
            try:
                _normalize_spectrum_config(sys_cfg.service, sys_cfg.spectrum, state.ras_station)
            except Exception as exc:
                spectrum_ready = False
                spectrum_issues.append(f"{label}: {exc}")

    # Build orbitals message
    if orbitals_ready:
        try:
            build_constellation_from_state(state)
        except Exception as exc:
            orbitals_ready = False
            orbitals_issues.append(str(exc))
    if orbitals_ready:
        if n_systems > 1:
            sys_details = []
            for s in all_systems:
                n_sats = sum(
                    int(b.num_sats_per_plane or 0) * int(b.plane_count or 0)
                    for b in s.belts
                )
                model = str(s.satellite_antennas.antenna_model or "none")
                sys_details.append(f"{s.system_name}: {n_sats:,} sats ({model})")
            orbitals_message = f"{n_systems} systems configured. " + "; ".join(sys_details)
        else:
            orbitals_message = "Constellation belts are ready."
    else:
        orbitals_message = "; ".join(orbitals_issues) if orbitals_issues else "Add at least one valid orbital belt."

    # Power summary (uses active system for display)
    s0 = state.active_system()
    try:
        power_input = _require_service_power_input(state)
        power_summary = _service_power_input_summary(power_input, uemr_mode=any_uemr)
    except ValueError:
        power_summary = None

    # Spectrum summary
    if any_uemr and spectrum_ready:
        _sp0 = s0.spectrum
        try:
            _start = float(_sp0.service_band_start_mhz)
            _stop = float(_sp0.service_band_stop_mhz)
            _mask = str(_sp0.unwanted_emission_mask_preset or "n/a")
            spectrum_summary = (
                f"UEMR: service band {_start:.3f}–{_stop:.3f} MHz | "
                f"transmit mask {_mask}."
            )
        except Exception:
            spectrum_summary = "UEMR spectrum inputs are ready."
    elif not spectrum_explicitly_configured:
        spectrum_summary = ""
        spectrum_ready = False
    elif spectrum_ready:
        try:
            spectrum_plan = _normalize_spectrum_config(
                s0.service, s0.spectrum, state.ras_station,
            )
            spectrum_summary = _spectrum_summary_text(spectrum_plan)
        except Exception as exc:
            spectrum_summary = str(exc)
            spectrum_ready = False
    else:
        spectrum_summary = "; ".join(spectrum_issues) if spectrum_issues else ""

    if run_in_progress:
        run_title = "Simulation is running"
        run_message_text = (
            "The run is active. Use the structured monitor below to track iteration, writer, and flush progress."
        )
    elif review_run_state == "completed":
        run_title = "Simulation finished"
        run_message_text = "The last run completed and the result file is ready for postprocess."
    elif review_run_state == "stopped":
        run_title = "Simulation stopped cleanly"
        run_message_text = (
            "The last run stopped with flushed partial results that can still be inspected."
        )
    else:
        run_title = "Review parameters and outputs" if run_ready else "Resolve run preflight blockers"
        run_message_text = (
            "Runtime, outputs, checkpoints, and storage are ready. Review the settings below before launching the run."
            if run_ready
            else run_message
        )
    run_completed = bool(run_in_progress or review_run_state in {"completed", "stopped"})

    return {
        "RAS Station": _workflow_status_payload(
            ready=bool(ras_ready),
            kind="ready" if ras_ready else "warning",
            title="RAS station is configured" if ras_ready else "Complete the RAS station",
            message=(
                "Station coordinates, local receive antenna inputs, and the RAS receiver response are ready."
                if ras_ready
                else (
                    "Set longitude, latitude, elevation, antenna diameter, a valid operational elevation range, "
                    f"and the RAS receiver band. {receiver_message}"
                )
            ),
            action="Open RAS station",
        ),
        "Satellite System Mode": _workflow_status_payload(
            # The default "MSS Directive (Cell Illumination)" is a legitimate
            # configuration out of the box, so the tab has no
            # failure state. But we still flag it as "not yet ready"
            # until the user actively opens the tab — that way a
            # fresh project nudges them to confirm (or change) the
            # mode instead of silently accepting the default.
            ready=bool(sat_sys_mode_visited),
            kind="ready" if sat_sys_mode_visited else "warning",
            title=(
                "UEMR (per-satellite bypass)"
                if _system_is_uemr(s0)
                else "MSS Directive (Cell Illumination)"
            ) if sat_sys_mode_visited else "Confirm the satellite system mode",
            message=(
                (
                    "UEMR active: every visible satellite radiates its configured Ptx/EIRP "
                    "isotropically. Beam library, coverage tabs, and the surface-PFD cap are "
                    "bypassed."
                    if _system_is_uemr(s0)
                    else "Directive transmit antenna: per-beam EIRP shaped by the satellite-antenna model, "
                    "coverage analyser and surface-PFD cap active."
                )
                if sat_sys_mode_visited
                else (
                    "The default is MSS Directive (Cell Illumination) (directive transmit antenna). "
                    "Open the tab to confirm, or switch to UEMR if you are modelling "
                    "unwanted per-satellite emissions."
                )
            ),
            action="Open Satellite System Mode",
        ),
        "Satellite Orbitals": _workflow_status_payload(
            ready=bool(orbitals_ready),
            kind="ready" if orbitals_ready else "warning",
            title="Satellite orbitals are configured" if orbitals_ready else "Add a constellation belt",
            message=orbitals_message,
            action="Open satellite orbitals",
        ),
        "Satellite Antennas": _workflow_status_payload(
            ready=bool(sat_ant_ready),
            kind="ready" if sat_ant_ready else "warning",
            title="Satellite antenna is configured"
            if sat_ant_ready
            else "Finish satellite antenna inputs",
            message=(
                "The satellite-system antenna model is ready for contours and simulation."
                if sat_ant_ready
                else ("; ".join(sat_ant_issues) if sat_ant_issues
                      else "Select a satellite antenna model and complete its required parameters.")
            ),
            action="Open satellite antennas",
        ),
        "Service & Demand": _workflow_status_payload(
            ready=bool(service_ready),
            kind="ready" if service_ready else "warning",
            title="Service and demand inputs are configured"
            if service_ready
            else "Complete service and demand inputs",
            message=(
                (
                    f"UEMR mode: {power_summary} is ready."
                    if any_uemr
                    else (
                        "Nco, Nbeam, selection, "
                        f"{_service_cell_activity_mode_label(str(s0.service.cell_activity_mode or _DEFAULT_SERVICE_CELL_ACTIVITY_MODE))} activity, "
                        f"and {power_summary} are ready."
                    )
                )
                if service_ready
                else ("; ".join(service_issues) if service_issues
                      else (
                          "Set one finite service power definition (Ptx or EIRP) "
                          "on the Service tab; UEMR mode skips Nco/Nbeam/"
                          "selection/cell activity and channel bandwidth."
                          if any_uemr
                          else "Set valid Nco, Nbeam, selection strategy, activity factor, channel bandwidth, and one finite service power definition, or apply the service defaults."
                      ))
            ),
            action="Open service and demand",
        ),
        "Spectrum & Reuse": _workflow_status_payload(
            ready=bool(spectrum_ready),
            kind="ready" if spectrum_ready else "warning",
            title=(
                "Spectrum plan is configured"
                if spectrum_ready and any_uemr
                else "Spectrum and reuse plan is configured"
            ) if spectrum_ready else (
                "Complete spectrum inputs"
                if any_uemr
                else "Complete spectrum and reuse inputs"
            ),
            message=(
                spectrum_summary
                if spectrum_ready
                else (
                    "Set a valid service band and transmitter unwanted-emission "
                    "mask; the RAS receiver band is defined on the RAS Station "
                    "tab. UEMR mode ignores cell-reuse settings."
                    if any_uemr
                    else "Set a valid service band, reuse factor, and transmitter "
                    "unwanted-emission mask, then use Edit Spectrum to choose "
                    "the simulated channels. The RAS receiver band is defined "
                    "on the RAS Station tab."
                )
            ),
            action="Open spectrum and reuse",
        ),
        "Coverage & Contours": _workflow_status_payload(
            ready=bool(contour_is_current) or any_uemr,
            kind=("ready" if (contour_is_current or any_uemr) else "warning"),
            title=(
                "Not applicable for UEMR mode"
                if any_uemr and not contour_is_current
                else ("Contour spacing is ready" if contour_is_current else "Refresh contour spacing")
            ),
            message=(
                "Coverage analyser is skipped in UEMR mode — an isotropic UEMR source has no finite beamwidth to resolve."
                if any_uemr and not contour_is_current
                else (
                    f"Effective cell spacing is locked at {float(effective_cell_km or 0.0):g} km."
                    if contour_is_current
                    else (
                        f"Stored contour spacing remains visible at {float(effective_cell_km or 0.0):g} km, but it is stale. "
                        "Rerun the analyser or use a valid override before preparing the active hexgrid."
                        if effective_cell_km is not None
                        else "Run the analyser or enable a cell-size override before preparing the active hexgrid."
                    )
                )
            ),
            action="Open contour analysis",
        ),
        "Coverage & Boresight": _workflow_status_payload(
            ready=bool(hexgrid_is_current) or any_uemr,
            kind=("ready" if (hexgrid_is_current or any_uemr) else "warning"),
            title=(
                "Not applicable for UEMR mode"
                if any_uemr and not hexgrid_is_current
                else (
                    "Hexgrid settings are current"
                    if hexgrid_is_current
                    else "Apply or preview the coverage and boresight settings"
                )
            ),
            message=(
                "Hexgrid / boresight avoidance do not apply to UEMR systems — all satellites radiate omnidirectionally with no beam pointing."
                if any_uemr and not hexgrid_is_current
                else (
                    "The current geography, RAS exclusion, and boresight settings are committed for this run."
                    if hexgrid_is_current
                    else hexgrid_status_message
                )
            ),
            action="Open coverage and boresight",
        ),
        "Review & Run": _workflow_status_payload(
            ready=bool(run_completed),
            review_pending=bool(run_ready and not run_completed),
            kind="ready" if (run_ready or run_completed) else "warning",
            title=run_title,
            message=run_message_text,
            action="Open review and run",
        ),
    }


class _WorkflowSummaryEmitter(QtCore.QObject):
    completed = QtCore.Signal(int, object)


def _effective_pattern_wavelength_cm(config: AntennasConfig | SatelliteAntennasConfig) -> float:
    return antenna.resolve_pattern_wavelength_cm(
        frequency_mhz=config.frequency_mhz,
        pattern_wavelength_cm=config.pattern_wavelength_cm,
        derive_from_frequency=config.derive_pattern_wavelength_from_frequency,
    )


def _effective_ras_pattern_wavelength_cm(config: AntennasConfig) -> float:
    """Resolve the wavelength used for the standalone RAS pattern preview.

    The RAS preview is allowed to use either the shared carrier frequency or an
    explicitly entered manual pattern wavelength. Unlike the satellite transmit
    pattern, it should not depend on the satellite-side derive toggle when the
    shared frequency is already known.
    """
    if config.derive_pattern_wavelength_from_frequency:
        return _effective_pattern_wavelength_cm(config)
    if config.pattern_wavelength_cm is not None:
        return float(config.pattern_wavelength_cm)
    if config.frequency_mhz is None:
        raise ValueError(
            "RAS pattern plots require a positive shared frequency or manual pattern wavelength."
        )
    return _pattern_wavelength_cm_from_frequency_mhz(float(config.frequency_mhz))


def _has_valid_ras_pattern_config(config: AntennasConfig | None) -> bool:
    if not _has_valid_ras_antenna_config(config):
        return False
    try:
        wavelength_cm = _effective_ras_pattern_wavelength_cm(config)
    except Exception:
        return False
    return float(wavelength_cm) > 0.0


def _has_valid_satellite_antenna_config(config: AntennasConfig | SatelliteAntennasConfig | None) -> bool:
    if config is None:
        return False
    if config.antenna_model is None:
        return False
    # UEMR isotropic mode doesn't need frequency/wavelength — the
    # kernel uses the shared frequency from the Service tab for FSPL.
    # Check early to avoid the wavelength resolution below failing
    # when the frequency fields are hidden/empty.
    if config.antenna_model == _ANTENNA_MODEL_ISOTROPIC:
        return True
    if config.frequency_mhz is None:
        return False
    if float(config.frequency_mhz) <= 0.0:
        return False
    try:
        wavelength_cm = _effective_pattern_wavelength_cm(config)
    except Exception:
        return False
    if wavelength_cm <= 0.0:
        return False
    if config.antenna_model in {_ANTENNA_MODEL_REC12, _ANTENNA_MODEL_S672}:
        return (
            config.rec12.gm_dbi is not None
            and config.rec12.ln_db is not None
            and config.rec12.z is not None
            and float(config.rec12.z) > 0.0
        )
    if config.antenna_model == _ANTENNA_MODEL_REC14:
        return (
            config.rec14.gm_dbi is not None
            and float(config.rec14.gm_dbi) > -300.0
            and config.rec14.lt_m is not None
            and config.rec14.lr_m is not None
            and config.rec14.l is not None
            and config.rec14.slr_db is not None
            and float(config.rec14.slr_db) > 0.0
            and config.rec14.far_sidelobe_start_deg is not None
            and config.rec14.far_sidelobe_level_dbi is not None
            and float(config.rec14.lt_m) > 0.0
            and float(config.rec14.lr_m) > 0.0
            and int(config.rec14.l) > 0
        )
    if config.antenna_model == _ANTENNA_MODEL_M2101:
        return (
            config.m2101.g_emax_dbi is not None
            and config.m2101.a_m_db is not None
            and config.m2101.sla_nu_db is not None
            and config.m2101.phi_3db_deg is not None
            and config.m2101.theta_3db_deg is not None
            and config.m2101.d_h is not None
            and config.m2101.d_v is not None
            and config.m2101.n_h is not None
            and config.m2101.n_v is not None
            and float(config.m2101.phi_3db_deg) > 0.0
            and float(config.m2101.theta_3db_deg) > 0.0
            and int(config.m2101.n_h) >= 1
            and int(config.m2101.n_v) >= 1
        )
    if config.antenna_model == _ANTENNA_MODEL_COLLAPSED:
        return True  # collapsed mode has no pattern requirements
    if config.antenna_model == _ANTENNA_MODEL_ISOTROPIC:
        return True  # isotropic / UEMR — no pattern parameters needed
    if config.antenna_model in (
        _ANTENNA_MODEL_CUSTOM_1D,
        _ANTENNA_MODEL_CUSTOM_2D,
    ):
        # Custom antenna pattern validity is derived entirely from the
        # embedded ``custom_pattern`` payload — the LUT plus the
        # ``peak_gain_dbi`` it carries fully defines the pattern, so
        # the Rec 1.2 / Rec 1.4 / M.2101 scalar fields are ignored.
        pat = getattr(config, "custom_pattern", None)
        if pat is None:
            return False
        expected_kind = (
            _CA_KIND_1D
            if config.antenna_model == _ANTENNA_MODEL_CUSTOM_1D
            else _CA_KIND_2D
        )
        return getattr(pat, "kind", None) == expected_kind
    return False


def _satellite_antenna_pattern_spec(
    config: AntennasConfig | SatelliteAntennasConfig,
) -> tuple[Callable[..., Any], u.Quantity, dict[str, Any]]:
    if not _has_valid_satellite_antenna_config(config):
        raise ValueError("Satellite-system antenna configuration is incomplete or invalid.")
    # Custom 1-D / 2-D patterns bypass ``build_satellite_pattern_spec``
    # (which is analytical-pattern-specific). The returned kwargs dict
    # carries ``custom_pattern`` which the GPU scenario dispatch
    # (``scenario.py``) routes to
    # ``session.prepare_custom_pattern_{1d,2d}_context``. The callable
    # is the CPU evaluator so existing preview / spec-inspection code
    # paths work transparently.
    if config.antenna_model in (_ANTENNA_MODEL_CUSTOM_1D, _ANTENNA_MODEL_CUSTOM_2D):
        from scepter.custom_antenna import evaluate_pattern_1d, evaluate_pattern_2d
        wl_cm = antenna.resolve_pattern_wavelength_cm(
            frequency_mhz=config.frequency_mhz,
            pattern_wavelength_cm=config.pattern_wavelength_cm,
            derive_from_frequency=bool(config.derive_pattern_wavelength_from_frequency),
        )
        wavelength = float(wl_cm) * u.cm
        pattern_obj = getattr(config, "custom_pattern", None)
        if pattern_obj is None:  # pragma: no cover — guarded by _has_valid_...
            raise ValueError("Custom antenna model selected but custom_pattern is None.")
        # Scenario dispatch reads ``custom_pattern`` out of the kwargs
        # dict by key; GUI preview (``_plot_antenna_pattern``) calls
        # the returned callable directly as
        # ``antenna_func(angles, wavelength=..., **pattern_kwargs)``.
        # The raw CPU evaluators take ``(pattern, angles)`` positionally,
        # which doesn't match either caller shape. Wrap them in
        # adapter closures so both call paths work: scenario dispatch
        # reads the dict key, and GUI preview's keyword-call shape
        # flows through the closure's ``**_`` sink.
        if config.antenna_model == _ANTENNA_MODEL_CUSTOM_1D:
            def _custom_1d_antenna_func(angles, *, wavelength=None, custom_pattern, **_):
                del wavelength  # not used by the LUT evaluator
                angles_deg = (
                    angles.to_value(u.deg) if hasattr(angles, "to_value")
                    else np.asarray(angles, dtype=np.float64)
                )
                return evaluate_pattern_1d(custom_pattern, angles_deg) * cnv.dBi
            return (_custom_1d_antenna_func, wavelength, {"custom_pattern": pattern_obj})

        def _custom_2d_antenna_func(
            axis0, axis1=None, *, wavelength=None, custom_pattern, **_,
        ):
            del wavelength
            a0 = (
                axis0.to_value(u.deg) if hasattr(axis0, "to_value")
                else np.asarray(axis0, dtype=np.float64)
            )
            # GUI preview passes a single ``offset_angles`` 1-D array.
            # Treat that as the off-boresight polar angle θ (for
            # ``grid_mode="theta_phi"``) at φ=0, or as ``az`` at el=0
            # (for ``grid_mode="az_el"``) — the "principal-plane"
            # preview cut. Full 2-D display is the job of the
            # dedicated preview dialog (Stage 21).
            if axis1 is None:
                axis1 = np.zeros_like(a0, dtype=np.float64)
            else:
                axis1 = (
                    axis1.to_value(u.deg) if hasattr(axis1, "to_value")
                    else np.asarray(axis1, dtype=np.float64)
                )
            return evaluate_pattern_2d(custom_pattern, a0, axis1) * cnv.dBi
        return (_custom_2d_antenna_func, wavelength, {"custom_pattern": pattern_obj})
    return antenna.build_satellite_pattern_spec(
        antenna_model=str(config.antenna_model),
        frequency_mhz=config.frequency_mhz,
        pattern_wavelength_cm=config.pattern_wavelength_cm,
        derive_pattern_wavelength_from_frequency=bool(
            config.derive_pattern_wavelength_from_frequency
        ),
        rec12_gm_dbi=config.rec12.gm_dbi,
        rec12_ln_db=config.rec12.ln_db,
        rec12_z=config.rec12.z,
        rec14_lt_m=config.rec14.lt_m,
        rec14_lr_m=config.rec14.lr_m,
        rec14_l=config.rec14.l,
        rec14_gm_dbi=config.rec14.gm_dbi,
        rec14_slr_db=config.rec14.slr_db,
        rec14_far_sidelobe_start_deg=config.rec14.far_sidelobe_start_deg,
        rec14_far_sidelobe_level_dbi=config.rec14.far_sidelobe_level_dbi,
        m2101_g_emax_dbi=config.m2101.g_emax_dbi,
        m2101_a_m_db=config.m2101.a_m_db,
        m2101_sla_nu_db=config.m2101.sla_nu_db,
        m2101_phi_3db_deg=config.m2101.phi_3db_deg,
        m2101_theta_3db_deg=config.m2101.theta_3db_deg,
        m2101_d_h=config.m2101.d_h,
        m2101_d_v=config.m2101.d_v,
        m2101_n_h=config.m2101.n_h,
        m2101_n_v=config.m2101.n_v,
        isotropic_uemr_mode=bool(getattr(config, "isotropic", AntennaIsotropicConfig()).uemr_mode),
        use_numba=False,
    )


def _allocate_unique_belt_name(
    seed_name: str,
    existing_names: Sequence[str],
    *,
    reserved_names: Sequence[str] = (),
) -> str:
    text = str(seed_name).strip() or "System3_Belt"
    stem = re.sub(r"_\d+$", "", text).strip("_") or "System3_Belt"
    taken = {str(name).strip() for name in existing_names}
    taken.update(str(name).strip() for name in reserved_names)
    candidate = text
    if candidate and candidate not in taken:
        return candidate
    suffix = 1
    while True:
        candidate = f"{stem}_{suffix}"
        if candidate not in taken:
            return candidate
        suffix += 1


def _parse_theta2_cell_ids_text(text: str) -> np.ndarray:
    text_use = str(text).strip()
    if text_use == "":
        return np.empty(0, dtype=np.int32)
    tokens = [token for token in re.split(r"[\s,;]+", text_use) if token]
    try:
        values = np.asarray([int(token) for token in tokens], dtype=np.int32)
    except ValueError as exc:
        raise ValueError(
            "θ₂ cell IDs must be integers separated by commas, spaces, or semicolons."
        ) from exc
    if np.any(values < 0):
        raise ValueError("θ₂ cell IDs must be non-negative.")
    return np.unique(values.astype(np.int32, copy=False))


def _runtime_gpu_method_constant(name: str) -> Any:
    method_name = str(name).strip().lower()
    mapping = {
        "dwarner": gpu_accel.METHOD_DWARNER,
        "vallado": gpu_accel.METHOD_VALLADO,
    }
    if method_name not in mapping:
        raise ValueError(f"Unsupported GPU method {name!r}.")
    return mapping[method_name]


def _runtime_dtype_constant(name: str) -> Any:
    dtype_name = str(name).strip().lower()
    mapping = {
        "float16": np.float16,
        "float32": np.float32,
        "float64": np.float64,
    }
    if dtype_name not in mapping:
        raise ValueError(f"Unsupported dtype {name!r}.")
    return mapping[dtype_name]


def _orbit_radius_m_per_sat(constellation: Mapping[str, Any]) -> np.ndarray:
    belt_sats = np.asarray(constellation["belt_sats"], dtype=np.int64)
    altitudes_q = u.Quantity(constellation["altitudes_q"]).to(u.m)
    sat_r = np.empty(int(np.sum(belt_sats, dtype=np.int64)), dtype=np.float32)
    start = 0
    for sat_count_obj, altitude_obj in zip(belt_sats, altitudes_q):
        sat_count = int(sat_count_obj)
        stop = start + sat_count
        sat_r[start:stop] = np.float32(R_earth.to_value(u.m) + float(altitude_obj.to_value(u.m)))
        start = stop
    return sat_r


def _default_camera_state() -> tuple[float, float, float]:
    return (35.0, 22.5, _CAMERA_DEFAULT_RADIUS_KM)


def _to_utc_datetime(value: datetime) -> datetime:
    if value.tzinfo is None:
        return value.replace(tzinfo=timezone.utc)
    return value.astimezone(timezone.utc)


def _qdatetime_to_utc_datetime(value: QtCore.QDateTime) -> datetime:
    secs = int(value.toSecsSinceEpoch())
    return datetime.fromtimestamp(secs, tz=timezone.utc)


def _utc_datetime_to_qdatetime(value: datetime) -> QtCore.QDateTime:
    dt_utc = _to_utc_datetime(value)
    return QtCore.QDateTime.fromSecsSinceEpoch(
        int(dt_utc.timestamp()),
        _UTC_TIMEZONE,
    )


def _geodetic_to_cartesian_km(
    longitude_deg: np.ndarray,
    latitude_deg: np.ndarray,
    altitude_km: np.ndarray,
) -> np.ndarray:
    lon_rad = np.deg2rad(np.asarray(longitude_deg, dtype=np.float64))
    lat_rad = np.deg2rad(np.asarray(latitude_deg, dtype=np.float64))
    radius_km = _EARTH_RADIUS_KM + np.asarray(altitude_km, dtype=np.float64)
    cos_lat = np.cos(lat_rad)
    x = radius_km * cos_lat * np.cos(lon_rad)
    y = radius_km * cos_lat * np.sin(lon_rad)
    z = radius_km * np.sin(lat_rad)
    return np.stack((x, y, z), axis=-1).astype(np.float32, copy=False)


def _cartesian_to_longitude_latitude_deg(points_km: np.ndarray) -> tuple[np.ndarray, np.ndarray]:
    points = np.asarray(points_km, dtype=np.float64)
    radii = np.linalg.norm(points, axis=-1)
    radii = np.maximum(radii, np.finfo(np.float64).tiny)
    longitude_deg = np.rad2deg(np.arctan2(points[..., 1], points[..., 0]))
    latitude_deg = np.rad2deg(np.arcsin(np.clip(points[..., 2] / radii, -1.0, 1.0)))
    return longitude_deg, latitude_deg


def _compute_earth_texture_coordinates(
    points_km: np.ndarray,
    *,
    longitude_offset_deg: float = _EARTH_TEXTURE_LONGITUDE_OFFSET_DEG,
) -> np.ndarray:
    """Map Cartesian Earth-surface points onto equirectangular UV coordinates."""
    longitude_deg, latitude_deg = _cartesian_to_longitude_latitude_deg(points_km)
    seam_longitude_deg = -180.0 - float(longitude_offset_deg)
    u_coord = (longitude_deg - seam_longitude_deg) / 360.0
    v_coord = (latitude_deg + 90.0) / 180.0
    u_wrapped = np.mod(u_coord, 1.0)
    eps = np.finfo(np.float32).eps
    seam_mask = np.isclose(u_wrapped, 0.0) & (longitude_deg > seam_longitude_deg)
    u_wrapped = np.where(seam_mask, 1.0 - eps, u_wrapped)
    return np.stack(
        (
            u_wrapped.astype(np.float32, copy=False),
            np.clip(v_coord, 0.0, 1.0).astype(np.float32, copy=False),
        ),
        axis=-1,
    )


def _copy_polydata(mesh: pv.DataSet) -> pv.PolyData:
    return pv.PolyData(mesh.copy(deep=True))


def _configure_viewer_texture(texture: pv.Texture | None) -> pv.Texture | None:
    if texture is None:
        return None
    for method_name in ("InterpolateOn", "MipmapOn", "RepeatOff", "SetQualityTo32Bit"):
        method = getattr(texture, method_name, None)
        if callable(method):
            try:
                method()
            except Exception:
                pass
    return texture


def _build_textured_earth_mesh() -> pv.PolyData:
    lon_count = 180
    lat_count = 90
    seam_longitude_deg = -180.0 - float(_EARTH_TEXTURE_LONGITUDE_OFFSET_DEG)
    longitudes = np.linspace(
        seam_longitude_deg,
        seam_longitude_deg + 360.0,
        lon_count + 1,
        dtype=np.float64,
    )
    latitudes = np.linspace(-90.0, 90.0, lat_count + 1, dtype=np.float64)
    lon_grid_deg, lat_grid_deg = np.meshgrid(longitudes, latitudes, indexing="xy")
    earth_points = _geodetic_to_cartesian_km(
        lon_grid_deg,
        lat_grid_deg,
        np.zeros_like(lon_grid_deg, dtype=np.float64),
    )
    faces: list[int] = []
    stride = lon_count + 1
    for lat_idx in range(lat_count):
        row_start = lat_idx * stride
        next_row_start = (lat_idx + 1) * stride
        for lon_idx in range(lon_count):
            p0 = row_start + lon_idx
            p1 = p0 + 1
            p2 = next_row_start + lon_idx
            p3 = p2 + 1
            faces.extend((3, p0, p2, p1))
            faces.extend((3, p1, p2, p3))
    earth_poly = pv.PolyData(
        earth_points.reshape(-1, 3),
        np.asarray(faces, dtype=np.int64),
    )
    u_coord = (lon_grid_deg - seam_longitude_deg) / 360.0
    v_coord = (lat_grid_deg + 90.0) / 180.0
    earth_poly.active_texture_coordinates = np.stack(
        (
            np.clip(u_coord, 0.0, 1.0).astype(np.float32, copy=False),
            np.clip(v_coord, 0.0, 1.0).astype(np.float32, copy=False),
        ),
        axis=-1,
    ).reshape(-1, 2)
    earth_poly = earth_poly.compute_normals(
        cell_normals=False,
        split_vertices=False,
        auto_orient_normals=True,
        inplace=False,
    )
    return earth_poly


def _load_earth_assets() -> tuple[pv.PolyData, pv.Texture]:
    mesh_cached = _EARTH_ASSET_CACHE.get("mesh")
    texture_cached = _EARTH_ASSET_CACHE.get("texture")
    if isinstance(mesh_cached, pv.PolyData) and isinstance(texture_cached, pv.Texture):
        return mesh_cached, texture_cached
    earth_mesh = _build_textured_earth_mesh()
    earth_texture: pv.Texture | None = None
    if _EARTH_TEXTURE_ASSET_PATH.exists():
        try:
            earth_texture = pv.read_texture(str(_EARTH_TEXTURE_ASSET_PATH))
        except Exception:
            earth_texture = None
    if earth_texture is None:
        earth_texture = pv_examples.load_globe_texture()
    earth_texture = _configure_viewer_texture(earth_texture)
    _EARTH_ASSET_CACHE["mesh"] = earth_mesh
    _EARTH_ASSET_CACHE["texture"] = earth_texture
    return earth_mesh, earth_texture


def _load_skybox_texture(mode: str) -> pv.Texture | None:
    mode_use = str(mode).strip()
    if mode_use == "Off":
        return None
    cached = _SKYBOX_TEXTURE_CACHE.get(mode_use)
    if isinstance(cached, pv.Texture):
        return cached
    if mode_use == "4K":
        texture = pv_examples.download_cubemap_space_4k()
    elif mode_use == "16K":
        texture = pv_examples.download_cubemap_space_16k()
    else:
        raise ValueError(f"Unsupported skybox mode: {mode_use!r}")
    _SKYBOX_TEXTURE_CACHE[mode_use] = texture
    return texture


_STARFIELD_CACHE: dict[str, pv.PolyData | None] = {}


def _build_starfield(n_stars: int = 6000, radius_km: float = 2_000_000.0) -> pv.PolyData:
    """Build a procedural starfield as a point cloud on a large sphere."""
    cached = _STARFIELD_CACHE.get("stars")
    if isinstance(cached, pv.PolyData) and cached.n_points == n_stars:
        return cached
    rng = np.random.default_rng(42)
    # Uniform distribution on sphere via Marsaglia method
    z = rng.uniform(-1.0, 1.0, n_stars).astype(np.float32)
    phi = rng.uniform(0.0, 2.0 * np.pi, n_stars).astype(np.float32)
    r_xy = np.sqrt(1.0 - z * z)
    x = r_xy * np.cos(phi) * radius_km
    y = r_xy * np.sin(phi) * radius_km
    z_pos = z * radius_km
    pts = np.column_stack((x, y, z_pos))
    # Vary brightness: mix of bright (few) and dim (many) stars
    brightness = rng.exponential(0.3, n_stars).clip(0.0, 1.0).astype(np.float32)
    poly = pv.PolyData(pts)
    poly["brightness"] = brightness
    _STARFIELD_CACHE["stars"] = poly
    return poly


def _build_orbit_ring(
    alt_km: float, ecc: float, inc_rad: float, argp_rad: float, raan_rad: float,
    n_pts: int = 120,
) -> pv.PolyData:
    """Build a single closed polyline representing one orbital plane ring."""
    R_EARTH_KM = 6378.137
    r_perigee = R_EARTH_KM + alt_km
    a_km = r_perigee / (1.0 - ecc) if ecc < 1.0 else r_perigee
    theta = np.linspace(0, 2.0 * np.pi, n_pts, endpoint=False, dtype=np.float64)
    cos_t = np.cos(theta)
    r_vals = a_km * (1.0 - ecc ** 2) / (1.0 + ecc * cos_t)
    u_vals = argp_rad + theta
    cos_u, sin_u = np.cos(u_vals), np.sin(u_vals)
    cos_i, sin_i = np.cos(inc_rad), np.sin(inc_rad)
    cos_O, sin_O = np.cos(raan_rad), np.sin(raan_rad)
    x = r_vals * (cos_O * cos_u - sin_O * sin_u * cos_i)
    y = r_vals * (sin_O * cos_u + cos_O * sin_u * cos_i)
    z = r_vals * sin_u * sin_i
    pts = np.column_stack((x, y, z)).astype(np.float32)
    lines = np.empty(n_pts + 2, dtype=np.int64)
    lines[0] = n_pts + 1
    lines[1:n_pts + 1] = np.arange(n_pts)
    lines[n_pts + 1] = 0  # close the ring
    ring = pv.PolyData(pts)
    ring.lines = lines
    return ring


def _make_earth_grid_lines(
    *,
    lon_step_deg: int = 30,
    lat_step_deg: int = 30,
    n_samples: int = 180,
) -> pv.PolyData:
    points: list[np.ndarray] = []
    lines: list[int] = []
    point_offset = 0

    lon_values = np.arange(-180.0, 180.0 + 0.1, float(lon_step_deg))
    lat_curve = np.linspace(-90.0, 90.0, int(n_samples), dtype=np.float64)
    lon_curve = np.linspace(-180.0, 180.0, int(n_samples), dtype=np.float64)

    for lon_deg in lon_values:
        curve = _geodetic_to_cartesian_km(
            np.full(lat_curve.shape, lon_deg, dtype=np.float64),
            lat_curve,
            np.zeros(lat_curve.shape, dtype=np.float64),
        )
        points.append(curve)
        lines.extend([curve.shape[0], *range(point_offset, point_offset + curve.shape[0])])
        point_offset += int(curve.shape[0])

    lat_values = np.arange(-60.0, 60.0 + 0.1, float(lat_step_deg))
    for lat_deg in lat_values:
        curve = _geodetic_to_cartesian_km(
            lon_curve,
            np.full(lon_curve.shape, lat_deg, dtype=np.float64),
            np.zeros(lon_curve.shape, dtype=np.float64),
        )
        points.append(curve)
        lines.extend([curve.shape[0], *range(point_offset, point_offset + curve.shape[0])])
        point_offset += int(curve.shape[0])

    if not points:
        return pv.PolyData()
    poly = pv.PolyData(np.vstack(points))
    poly.lines = np.asarray(lines, dtype=np.int32)
    return poly


def _default_preview_parameters() -> PreviewParameters:
    start = datetime.now(timezone.utc).replace(microsecond=0)
    return PreviewParameters(
        start_utc=start,
        end_utc=start + timedelta(seconds=_DEFAULT_VIEWER_SPAN_S),
        frame_step_s=_DEFAULT_VIEWER_FRAME_STEP_S,
        playback_fps=_DEFAULT_VIEWER_PLAYBACK_FPS,
    )


def _build_preview_mjds(
    start_utc: datetime,
    end_utc: datetime,
    frame_step_s: float,
) -> tuple[np.ndarray, list[datetime]]:
    start_time = Time(start_utc)
    end_time = Time(end_utc)
    step_days = frame_step_s / 86400.0
    mjds = np.arange(
        start_time.mjd,
        end_time.mjd + 0.5 * step_days,
        step_days,
        dtype=np.float64,
    )
    if mjds.size < 1:
        mjds = np.asarray([start_time.mjd, end_time.mjd], dtype=np.float64)
    elif mjds[-1] < end_time.mjd - 1.0e-12:
        mjds = np.concatenate((mjds, np.asarray([end_time.mjd], dtype=np.float64)))
    frame_times = [
        _to_utc_datetime(Time(mjd, format="mjd").to_datetime(timezone=timezone.utc))
        for mjd in mjds.tolist()
    ]
    return mjds, frame_times


def _compute_earth_rotation_deg(times_utc: Sequence[datetime]) -> np.ndarray:
    times = Time(list(times_utc))
    return np.asarray(
        times.sidereal_time("mean", "greenwich").to_value(u.deg),
        dtype=np.float32,
    )


def _merge_polydata_parts(parts: Sequence[pv.DataSet]) -> pv.PolyData:
    merged = _copy_polydata(parts[0])
    for part in parts[1:]:
        merged = _copy_polydata(merged.merge(part, merge_points=False))
    return _copy_polydata(merged.extract_surface().triangulate())


def _build_parabolic_dish(
    *,
    radius_km: float,
    depth_km: float,
    radial_resolution: int,
    angular_resolution: int,
) -> pv.PolyData:
    radial = np.linspace(0.0, radius_km, int(radial_resolution), dtype=np.float32)
    azimuth = np.linspace(0.0, 2.0 * np.pi, int(angular_resolution), endpoint=True, dtype=np.float32)
    rr, aa = np.meshgrid(radial, azimuth, indexing="ij")
    focal_length = (radius_km * radius_km) / max(4.0 * depth_km, np.finfo(np.float32).tiny)
    xx = rr * np.cos(aa)
    yy = rr * np.sin(aa)
    zz = -(rr * rr) / (4.0 * focal_length)
    grid = pv.StructuredGrid(
        np.ascontiguousarray(xx),
        np.ascontiguousarray(yy),
        np.ascontiguousarray(zz),
    )
    return _copy_polydata(grid.extract_surface().triangulate())


def _build_satellite_mesh(render_mode: str) -> pv.PolyData:
    cache_key = f"satellite:{render_mode}"
    cached = _MODEL_MESH_CACHE.get(cache_key)
    if isinstance(cached, pv.PolyData):
        return cached

    mode_fast = render_mode == "Fast"
    if mode_fast:
        mesh = pv.Icosphere(radius=25.0, nsub=0)  # 12 vertices, 20 triangles
        _MODEL_MESH_CACHE[cache_key] = mesh
        return mesh

    body_length = 200.0
    body_width = 68.0
    body_height = 54.0
    panel_length = 260.0
    panel_width = 40.0
    panel_height = 9.0
    body = pv.Box(
        bounds=(
            -0.5 * body_length,
            0.5 * body_length,
            -0.5 * body_width,
            0.5 * body_width,
            -0.5 * body_height,
            0.5 * body_height,
        )
    )
    panel_offset = 0.5 * (body_width + panel_width) + 4.0
    panel_left = pv.Box(
        bounds=(
            -0.5 * panel_length,
            0.5 * panel_length,
            -panel_offset - 0.5 * panel_width,
            -panel_offset + 0.5 * panel_width,
            -0.5 * panel_height,
            0.5 * panel_height,
        )
    )
    panel_right = pv.Box(
        bounds=(
            -0.5 * panel_length,
            0.5 * panel_length,
            panel_offset - 0.5 * panel_width,
            panel_offset + 0.5 * panel_width,
            -0.5 * panel_height,
            0.5 * panel_height,
        )
    )
    parts: list[pv.DataSet] = [body]
    if not mode_fast:
        parts.extend((panel_left, panel_right))
    if not mode_fast:
        antenna = pv.Cylinder(
            center=(0.35 * body_length, 0.0, 0.0),
            direction=(1.0, 0.0, 0.0),
            radius=10.0,
            height=28.0,
            resolution=28,
        )
        radiator = pv.Box(
            bounds=(
                -0.25 * body_length,
                0.05 * body_length,
                -10.0,
                10.0,
                0.5 * body_height,
                0.5 * body_height + 10.0,
            )
        )
        parts.extend((antenna, radiator))
    mesh = _merge_polydata_parts(parts)
    _MODEL_MESH_CACHE[cache_key] = mesh
    return mesh


def _build_ras_station_mesh(render_mode: str) -> pv.PolyData:
    cache_key = f"ras:{render_mode}"
    cached = _MODEL_MESH_CACHE.get(cache_key)
    if isinstance(cached, pv.PolyData):
        return cached

    mode_fast = render_mode == "Fast"
    base_radius = 15.0 if mode_fast else 33.0
    pole_height = 108.0 if mode_fast else 202.5
    pole_radius = 6.0 if mode_fast else 11.25
    dish_radius = 30.0 if mode_fast else 69.0
    dish_depth = 7.5 if mode_fast else 21.0
    base = pv.Cylinder(
        center=(0.0, 0.0, 8.0),
        direction=(0.0, 0.0, 1.0),
        radius=base_radius,
        height=16.0,
        resolution=24,
    )
    pole = pv.Cylinder(
        center=(0.0, 0.0, 16.0 + 0.5 * pole_height),
        direction=(0.0, 0.0, 1.0),
        radius=pole_radius,
        height=pole_height,
        resolution=18,
    )
    dish = _build_parabolic_dish(
        radius_km=dish_radius,
        depth_km=dish_depth,
        radial_resolution=8 if mode_fast else 20,
        angular_resolution=18 if mode_fast else 42,
    )
    dish.translate((0.0, 0.0, 16.0 + pole_height), inplace=True)
    parts: list[pv.DataSet] = [base, pole, dish]
    if not mode_fast:
        support_arm = pv.Cylinder(
            center=(0.0, 0.0, 16.0 + pole_height + 6.0),
            direction=(0.0, 0.0, 1.0),
            radius=3.75,
            height=30.0,
            resolution=12,
        )
        receiver = pv.Sphere(
            radius=6.0,
            center=(0.0, 0.0, 16.0 + pole_height + 27.0),
            theta_resolution=16,
            phi_resolution=16,
        )
        parts.extend((support_arm, receiver))
    mesh = _merge_polydata_parts(parts)
    _MODEL_MESH_CACHE[cache_key] = mesh
    return mesh


def _rotation_matrix_from_vectors(
    source_vector: np.ndarray,
    target_vector: np.ndarray,
) -> np.ndarray:
    source = np.asarray(source_vector, dtype=np.float64)
    target = np.asarray(target_vector, dtype=np.float64)
    source /= max(np.linalg.norm(source), np.finfo(np.float64).tiny)
    target /= max(np.linalg.norm(target), np.finfo(np.float64).tiny)
    cross = np.cross(source, target)
    dot = float(np.clip(np.dot(source, target), -1.0, 1.0))
    cross_norm = np.linalg.norm(cross)
    if cross_norm <= 1.0e-12:
        if dot > 0.0:
            return np.eye(3, dtype=np.float64)
        trial_axis = np.array([1.0, 0.0, 0.0], dtype=np.float64)
        if abs(source[0]) > 0.9:
            trial_axis = np.array([0.0, 1.0, 0.0], dtype=np.float64)
        axis = np.cross(source, trial_axis)
        axis /= max(np.linalg.norm(axis), np.finfo(np.float64).tiny)
        return -np.eye(3, dtype=np.float64) + 2.0 * np.outer(axis, axis)
    axis = cross / cross_norm
    skew = np.array(
        (
            (0.0, -axis[2], axis[1]),
            (axis[2], 0.0, -axis[0]),
            (-axis[1], axis[0], 0.0),
        ),
        dtype=np.float64,
    )
    angle = float(np.arccos(dot))
    return (
        np.eye(3, dtype=np.float64)
        + np.sin(angle) * skew
        + (1.0 - np.cos(angle)) * (skew @ skew)
    )


def _rotation_matrix_z(angle_deg: float) -> np.ndarray:
    angle_rad = np.deg2rad(float(angle_deg))
    cos_ang = float(np.cos(angle_rad))
    sin_ang = float(np.sin(angle_rad))
    return np.asarray(
        (
            (cos_ang, -sin_ang, 0.0),
            (sin_ang, cos_ang, 0.0),
            (0.0, 0.0, 1.0),
        ),
        dtype=np.float32,
    )


def _rotate_points_about_z(points: np.ndarray, angle_deg: float) -> np.ndarray:
    rotation = _rotation_matrix_z(angle_deg)
    return np.asarray(points, dtype=np.float32) @ rotation.T


def _interpolate_scalar_series(
    sample_times_s: np.ndarray,
    values: np.ndarray,
    offset_s: float,
) -> float:
    if values.size < 1:
        return 0.0
    if values.size == 1 or offset_s <= float(sample_times_s[0]):
        return float(values[0])
    if offset_s >= float(sample_times_s[-1]):
        return float(values[-1])
    upper_idx = int(np.searchsorted(sample_times_s, offset_s, side="right"))
    lower_idx = max(upper_idx - 1, 0)
    upper_idx = min(upper_idx, values.size - 1)
    if upper_idx == lower_idx:
        return float(values[lower_idx])
    t0 = float(sample_times_s[lower_idx])
    t1 = float(sample_times_s[upper_idx])
    frac = float((offset_s - t0) / max(t1 - t0, np.finfo(np.float32).tiny))
    return float(values[lower_idx] + frac * (values[upper_idx] - values[lower_idx]))


def _interpolate_position_frames(
    sample_times_s: np.ndarray,
    frame_values: np.ndarray,
    offset_s: float,
    out: np.ndarray | None = None,
) -> np.ndarray:
    n_frames = frame_values.shape[0]
    if n_frames < 1:
        return np.empty((0, 3), dtype=np.float32)
    # Allocate or reuse output buffer
    if out is None or out.shape != frame_values.shape[1:]:
        out = np.empty(frame_values.shape[1:], dtype=np.float32)
    if n_frames == 1 or offset_s <= float(sample_times_s[0]):
        np.copyto(out, frame_values[0], casting="unsafe")
        return out
    if offset_s >= float(sample_times_s[-1]):
        np.copyto(out, frame_values[-1], casting="unsafe")
        return out
    upper_idx = int(np.searchsorted(sample_times_s, offset_s, side="right"))
    lower_idx = max(upper_idx - 1, 0)
    upper_idx = min(upper_idx, n_frames - 1)
    if upper_idx == lower_idx:
        np.copyto(out, frame_values[lower_idx], casting="unsafe")
        return out
    t0 = float(sample_times_s[lower_idx])
    t1 = float(sample_times_s[upper_idx])
    frac = np.float32((offset_s - t0) / max(t1 - t0, np.finfo(np.float32).tiny))
    # Allocation-free in-place blend:
    #   out = upper - lower
    #   out *= frac
    #   out += lower
    # Avoids the (S, 3) temporary that ``frac * frame_values[upper_idx]``
    # used to allocate every frame (~40 KB per frame for 3 360 sats →
    # ~2.4 MB/s of GC pressure at 60 fps).
    lower = frame_values[lower_idx]
    upper = frame_values[upper_idx]
    np.subtract(upper, lower, out=out, casting="unsafe")
    out *= frac
    out += lower
    return out


def _interpolate_vector_frames(
    sample_times_s: np.ndarray,
    frame_values: np.ndarray,
    offset_s: float,
    out: np.ndarray | None = None,
) -> np.ndarray:
    return _interpolate_position_frames(sample_times_s, frame_values, offset_s, out=out)


def _set_actor_z_rotation(actor: Any, angle_deg: float) -> bool:
    if actor is None:
        return False
    if hasattr(actor, "SetOrientation"):
        actor.SetOrientation(0.0, 0.0, float(angle_deg))
        return True
    return False


def _local_orbital_frame(
    position_eci_km: np.ndarray,
    velocity_eci_km_s: np.ndarray,
) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
    z_axis = -np.asarray(position_eci_km, dtype=np.float64)
    z_axis /= max(np.linalg.norm(z_axis), np.finfo(np.float64).tiny)
    velocity = np.asarray(velocity_eci_km_s, dtype=np.float64)
    x_axis = velocity - np.dot(velocity, z_axis) * z_axis
    x_norm = np.linalg.norm(x_axis)
    if x_norm <= 1.0e-12:
        reference = np.array([0.0, 0.0, 1.0], dtype=np.float64)
        if abs(float(np.dot(reference, z_axis))) > 0.9:
            reference = np.array([0.0, 1.0, 0.0], dtype=np.float64)
        x_axis = np.cross(reference, z_axis)
        x_norm = np.linalg.norm(x_axis)
    x_axis /= max(x_norm, np.finfo(np.float64).tiny)
    y_axis = np.cross(z_axis, x_axis)
    y_axis /= max(np.linalg.norm(y_axis), np.finfo(np.float64).tiny)
    return x_axis, y_axis, z_axis


def _beam_direction_from_alpha_beta(
    position_eci_km: np.ndarray,
    velocity_eci_km_s: np.ndarray,
    *,
    alpha_deg: float,
    beta_deg: float,
) -> np.ndarray:
    x_axis, y_axis, z_axis = _local_orbital_frame(position_eci_km, velocity_eci_km_s)
    beta_rad = float(np.deg2rad(beta_deg))
    alpha_rad = 0.0 if abs(beta_deg) <= 1.0e-9 else float(np.deg2rad(alpha_deg))
    lateral = np.cos(alpha_rad) * x_axis + np.sin(alpha_rad) * y_axis
    direction = np.cos(beta_rad) * z_axis + np.sin(beta_rad) * lateral
    direction /= max(np.linalg.norm(direction), np.finfo(np.float64).tiny)
    return direction


def _ray_sphere_intersection(
    origin_km: np.ndarray,
    direction: np.ndarray,
    *,
    radius_km: float = _EARTH_RADIUS_KM,
) -> np.ndarray | None:
    origin = np.asarray(origin_km, dtype=np.float64)
    ray = np.asarray(direction, dtype=np.float64)
    ray /= max(np.linalg.norm(ray), np.finfo(np.float64).tiny)
    quadratic_b = 2.0 * float(np.dot(origin, ray))
    quadratic_c = float(np.dot(origin, origin) - radius_km * radius_km)
    discriminant = quadratic_b * quadratic_b - 4.0 * quadratic_c
    if discriminant < 0.0:
        return None
    root_disc = float(np.sqrt(discriminant))
    t_candidates = [(-quadratic_b - root_disc) / 2.0, (-quadratic_b + root_disc) / 2.0]
    positive_t = [value for value in t_candidates if value > 0.0]
    if not positive_t:
        return None
    t_use = min(positive_t)
    return origin + t_use * ray


def _orthonormal_basis_from_direction(direction: np.ndarray) -> tuple[np.ndarray, np.ndarray]:
    base_dir = np.asarray(direction, dtype=np.float64)
    base_dir /= max(np.linalg.norm(base_dir), np.finfo(np.float64).tiny)
    reference = np.array([0.0, 0.0, 1.0], dtype=np.float64)
    if abs(float(np.dot(reference, base_dir))) > 0.9:
        reference = np.array([0.0, 1.0, 0.0], dtype=np.float64)
    axis_u = np.cross(base_dir, reference)
    axis_u /= max(np.linalg.norm(axis_u), np.finfo(np.float64).tiny)
    axis_v = np.cross(base_dir, axis_u)
    axis_v /= max(np.linalg.norm(axis_v), np.finfo(np.float64).tiny)
    return axis_u, axis_v


def _resolve_contour_half_angle_deg(
    antennas_cfg: AntennasConfig,
    contour_drop: str | float,
) -> float:
    antenna_func, wavelength, pattern_kwargs = _satellite_antenna_pattern_spec(antennas_cfg)
    return earthgrid.resolve_contour_half_angle_deg(
        antenna_func,
        wavelength=wavelength,
        contour_drop=contour_drop,
        **pattern_kwargs,
    )


def _sample_contour_on_earth(
    position_eci_km: np.ndarray,
    velocity_eci_km_s: np.ndarray,
    *,
    alpha_deg: float,
    beta_deg: float,
    contour_half_angle_deg: float,
    n_samples: int = _CONTOUR_SAMPLE_COUNT,
) -> np.ndarray:
    boresight = _beam_direction_from_alpha_beta(
        position_eci_km,
        velocity_eci_km_s,
        alpha_deg=alpha_deg,
        beta_deg=beta_deg,
    )
    basis_u, basis_v = _orthonormal_basis_from_direction(boresight)
    contour_rad = float(np.deg2rad(contour_half_angle_deg))
    sample_angles = np.linspace(0.0, 2.0 * np.pi, int(n_samples), endpoint=False)
    intersections: list[np.ndarray] = []
    for sample_angle in sample_angles:
        ray_dir = (
            np.cos(contour_rad) * boresight
            + np.sin(contour_rad)
            * (np.cos(sample_angle) * basis_u + np.sin(sample_angle) * basis_v)
        )
        intersection = _ray_sphere_intersection(position_eci_km, ray_dir)
        if intersection is not None:
            intersections.append(intersection.astype(np.float32, copy=False))
    if not intersections:
        return np.empty((0, 3), dtype=np.float32)
    contour_points = np.vstack(intersections).astype(np.float32, copy=False)
    return contour_points


def _camera_vectors_from_state(
    longitude_deg: float,
    latitude_deg: float,
    radius_km: float,
) -> tuple[np.ndarray, np.ndarray]:
    lon_rad = np.deg2rad(float(longitude_deg))
    lat_rad = np.deg2rad(float(latitude_deg))
    radius = float(max(radius_km, _CAMERA_MIN_RADIUS_KM))
    position = np.asarray(
        (
            radius * np.cos(lat_rad) * np.cos(lon_rad),
            radius * np.cos(lat_rad) * np.sin(lon_rad),
            radius * np.sin(lat_rad),
        ),
        dtype=np.float64,
    )
    view_dir = -position / max(np.linalg.norm(position), np.finfo(np.float64).tiny)
    north = np.asarray((0.0, 0.0, 1.0), dtype=np.float64)
    view_up = north - np.dot(north, view_dir) * view_dir
    if np.linalg.norm(view_up) <= 1.0e-9:
        east = np.asarray((-np.sin(lon_rad), np.cos(lon_rad), 0.0), dtype=np.float64)
        view_up = np.cross(view_dir, east)
    view_up /= max(np.linalg.norm(view_up), np.finfo(np.float64).tiny)
    return position, view_up


def save_project_state(path: str | Path, state: ScepterProjectState) -> None:
    """
    Save a GUI configuration to JSON.

    Parameters
    ----------
    path : str or Path
        Destination JSON path.
    state : ScepterProjectState
        GUI state to persist.
    """
    Path(path).write_text(
        json.dumps(state.to_json_dict(), indent=2, sort_keys=True),
        encoding="utf-8",
    )


def load_project_state(path: str | Path) -> ScepterProjectState:
    """
    Load a GUI configuration from JSON.

    Parameters
    ----------
    path : str or Path
        Source JSON path.

    Returns
    -------
    ScepterProjectState
        Parsed GUI state.
    """
    payload = json.loads(Path(path).read_text(encoding="utf-8"))
    return ScepterProjectState.from_json_dict(payload)


def export_belt_definitions(
    state: ScepterProjectState,
    *,
    system_index: int = 0,
) -> list[dict[str, Any]]:
    """
    Convert GUI state into ``tleforger`` belt-definition dictionaries.

    Parameters
    ----------
    state : ScepterProjectState
        GUI state containing one or more belt rows.
    system_index : int, optional
        Which system's belts to export. Default 0 (active system).

    Returns
    -------
    list[dict[str, Any]]
        Belt-definition dictionaries ready for
        :func:`scepter.tleforger.forge_tle_constellation_from_belt_definitions`.
    """
    sys = state.active_system(system_index)
    return [belt.to_tleforger_dict() for belt in sys.belts]


def build_constellation_from_state(
    state: ScepterProjectState,
    *,
    all_systems: bool = False,
    start_time: datetime | None = None,
) -> dict[str, Any]:
    """
    Forge a constellation from the current GUI state.

    Parameters
    ----------
    state : ScepterProjectState
        GUI state.
    all_systems : bool, optional
        If True and ``state.systems`` has multiple entries, combine belts
        from all systems into a single constellation for preview purposes.

    Returns
    -------
    dict[str, Any]
        Forged constellation dictionary returned by
        :func:`scepter.tleforger.forge_tle_constellation_from_belt_definitions`.
    """
    if all_systems and len(state.systems) > 1:
        all_belts: list[BeltConfig] = []
        for sys_cfg in state.systems:
            all_belts.extend(sys_cfg.belts)
        if not all_belts:
            raise ValueError("No belts are defined in any system.")
        tleforger.reset_tle_counter()
        return tleforger.forge_tle_constellation_from_belt_definitions(
            [b.to_tleforger_dict() for b in all_belts],
            start_time=start_time,
        )
    s0_belts = state.active_system().belts
    if len(s0_belts) < 1:
        raise ValueError("No belts are defined.")
    tleforger.reset_tle_counter()
    return tleforger.forge_tle_constellation_from_belt_definitions(
        [b.to_tleforger_dict() for b in s0_belts],
        start_time=start_time,
    )


def validate_project_state(
    state: ScepterProjectState,
) -> tuple[bool, str, dict[str, Any] | None]:
    """
    Validate GUI state and produce a summary.

    Parameters
    ----------
    state : ScepterProjectState
        GUI state to validate.

    Returns
    -------
    tuple[bool, str, dict[str, Any] or None]
        ``(is_valid, summary_text, constellation)``. ``constellation`` is
        returned only when the state validates successfully.
    """
    lines: list[str] = []
    constellation: dict[str, Any] | None = None
    s0 = state.active_system()
    svc = s0.service
    if svc.nco is None or int(svc.nco) <= 0:
        return False, "Configuration error:\nNco must be positive.", None
    if svc.nbeam is None or int(svc.nbeam) <= 0:
        return False, "Configuration error:\nNbeam must be positive.", None
    if str(svc.selection_strategy or "") not in {value for _, value in _SELECTION_STRATEGY_OPTIONS}:
        return False, "Configuration error:\nSelection strategy is unsupported.", None
    if svc.cell_activity_factor is None or not (0.0 <= float(svc.cell_activity_factor) <= 1.0):
        return False, "Configuration error:\nCell activity must lie in [0, 100] %.", None
    try:
        _require_service_power_input(state)
    except ValueError:
        return (
            False,
            "Configuration error:\nChannel bandwidth and one finite service power definition are required.",
            None,
        )
    if float(state.runtime.atmosphere_elev_bin_deg) <= 0.0:
        return False, "Configuration error:\nAtmosphere elevation bin must be positive.", None
    if not (
        0.0 < float(state.runtime.atmosphere_elev_min_deg)
        < float(state.runtime.atmosphere_elev_max_deg)
        <= 90.0
    ):
        return (
            False,
            "Configuration error:\nAtmosphere elevation range must satisfy 0 < min < max <= 90 degrees.",
            None,
        )
    if float(state.runtime.atmosphere_max_path_length_km) <= 0.0:
        return False, "Configuration error:\nAtmosphere max path length must be positive.", None
    if float(state.runtime.host_memory_budget_gb) <= 0.0:
        return False, "Configuration error:\nHost memory budget must be positive.", None
    if float(state.runtime.gpu_memory_budget_gb) <= 0.0:
        return False, "Configuration error:\nGPU memory budget must be positive.", None
    if str(state.runtime.memory_budget_mode) not in set(_MEMORY_BUDGET_MODE_OPTIONS):
        return False, "Configuration error:\nMemory budget mode is unsupported.", None
    if str(state.runtime.memory_headroom_profile) not in set(_MEMORY_HEADROOM_PROFILE_OPTIONS):
        return False, "Configuration error:\nMemory headroom profile is unsupported.", None
    if str(state.runtime.scheduler_target_profile) not in {
        value for _label, value in _SCHEDULER_TARGET_PROFILE_OPTIONS
    }:
        return False, "Configuration error:\nScheduler target profile is unsupported.", None

    antennas_from_sys = s0.satellite_antennas.to_antennas_config(
        ras=state.ras_antenna,
    )
    if antennas_from_sys is not None and _has_any_antenna_value(antennas_from_sys):
        ras_antenna = state.ras_antenna
        if (
            ras_antenna.operational_elevation_min_deg is not None
            and ras_antenna.operational_elevation_max_deg is not None
            and not (
                0.0
                <= float(ras_antenna.operational_elevation_min_deg)
                < float(ras_antenna.operational_elevation_max_deg)
                <= 90.0
            )
        ):
            return (
                False,
                "Configuration error:\nRAS antenna operational elevation range must satisfy "
                "0 <= min < max <= 90 degrees.",
                None,
            )

    antennas_cfg = antennas_from_sys
    if antennas_cfg is not None and _has_any_antenna_value(antennas_cfg):
        if antennas_cfg.frequency_mhz is not None and float(antennas_cfg.frequency_mhz) <= 0.0:
            return False, "Configuration error:\nFrequency must be positive.", None
        try:
            pattern_wavelength_cm = _effective_pattern_wavelength_cm(antennas_cfg)
        except Exception:
            pattern_wavelength_cm = None
        if pattern_wavelength_cm is not None and pattern_wavelength_cm <= 0.0:
            return False, "Configuration error:\nPattern wavelength must be positive.", None
        if (
            antennas_cfg.antenna_model == _ANTENNA_MODEL_REC12
            and antennas_cfg.rec12.z is not None
            and float(antennas_cfg.rec12.z) <= 0.0
        ):
            return False, "Configuration error:\nRec 1.2 parameter z must be positive.", None
        if antennas_cfg.antenna_model == _ANTENNA_MODEL_REC14:
            if (
                antennas_cfg.rec14.lt_m is not None
                and float(antennas_cfg.rec14.lt_m) <= 0.0
            ) or (
                antennas_cfg.rec14.lr_m is not None
                and float(antennas_cfg.rec14.lr_m) <= 0.0
            ):
                return (
                    False,
                    "Configuration error:\nRec 1.4 aperture dimensions Lt and Lr must be positive.",
                    None,
                )
            if antennas_cfg.rec14.l is not None and int(antennas_cfg.rec14.l) <= 0:
                return False, "Configuration error:\nRec 1.4 parameter l must be positive.", None
        if antennas_cfg.antenna_model in (_ANTENNA_MODEL_CUSTOM_1D, _ANTENNA_MODEL_CUSTOM_2D):
            # Stage 22: a user switching back to a Custom model after
            # previously using Isotropic / Rec 1.2 / etc. may still have
            # ``custom_pattern=None`` (that field is hidden in the
            # Isotropic UI so the load happens separately). Surface
            # that with an actionable message — silent "incomplete
            # config" rejections are maddening to debug.
            expected_kind = (
                _CA_KIND_1D
                if antennas_cfg.antenna_model == _ANTENNA_MODEL_CUSTOM_1D
                else _CA_KIND_2D
            )
            pattern_obj = getattr(antennas_cfg, "custom_pattern", None)
            if pattern_obj is None:
                return (
                    False,
                    (
                        "Configuration error:\n"
                        f"Antenna model {antennas_cfg.antenna_model!r} requires a "
                        "custom_pattern — load a pattern file via the Satellite "
                        "Antennas tab's \"Load pattern\" button, or switch to a "
                        "different antenna model."
                    ),
                    None,
                )
            if getattr(pattern_obj, "kind", None) != expected_kind:
                return (
                    False,
                    (
                        "Configuration error:\n"
                        f"Antenna model {antennas_cfg.antenna_model!r} expects a "
                        f"custom_pattern of kind {expected_kind!r}; loaded "
                        f"pattern has kind {getattr(pattern_obj, 'kind', None)!r}. "
                        "Either load a matching pattern or switch the antenna "
                        "model to match the loaded pattern's kind."
                    ),
                    None,
                )
        if antennas_cfg.antenna_model not in {
            None, _ANTENNA_MODEL_REC12, _ANTENNA_MODEL_REC14,
            _ANTENNA_MODEL_M2101, _ANTENNA_MODEL_S672, _ANTENNA_MODEL_COLLAPSED,
            _ANTENNA_MODEL_ISOTROPIC,
            _ANTENNA_MODEL_CUSTOM_1D, _ANTENNA_MODEL_CUSTOM_2D,
        }:
            return (
                False,
                f"Configuration error:\nUnsupported antenna model {antennas_cfg.antenna_model!r}.",
                None,
            )
    try:
        _normalize_spectrum_config(svc, s0.spectrum, state.ras_station)
    except Exception as exc:
        return False, f"Configuration error:\nInvalid spectrum plan: {exc}", None
    if state.ras_station is not None and _has_any_ras_station_value(state.ras_station):
        if not _has_complete_ras_station_config(state.ras_station):
            lines.append("RAS station:")
            lines.append("  Incomplete geometry. Fill longitude, latitude, and elevation to use it.")
            lines.append("")

    if len(s0.belts) > 0:
        try:
            constellation = build_constellation_from_state(state)
        except Exception as exc:
            return False, f"Configuration error:\n{exc}", None
        summary = tleforger.summarize_constellation_geometry(constellation)
        lines.extend(summary["summary_lines"])
    else:
        lines.append("Constellation:")
        lines.append("  No belts defined.")

    lines.append("")
    lines.append("RAS station:")
    if state.ras_station is None or not _has_any_ras_station_value(state.ras_station):
        lines.append("  None configured.")
    elif not _has_complete_ras_station_config(state.ras_station):
        lines.append("  Incomplete geometry. Fill longitude, latitude, and elevation.")
    else:
        lines.append(
            f"  lon={state.ras_station.longitude_deg:.6f} deg, "
            f"lat={state.ras_station.latitude_deg:.6f} deg, "
            f"elev={state.ras_station.elevation_m:.1f} m"
        )

    lines.append("")
    lines.append("Antennas:")
    if antennas_cfg is None or not _has_any_antenna_value(antennas_cfg):
        lines.append("  None configured.")
    else:
        if _has_valid_satellite_antenna_config(antennas_cfg):
            lines.append(f"  frequency={antennas_cfg.frequency_mhz:.3f} MHz")
            lines.append(
                f"  pattern wavelength={_effective_pattern_wavelength_cm(antennas_cfg):.3f} cm"
                + (" (derived)" if antennas_cfg.derive_pattern_wavelength_from_frequency else " (manual)")
            )
            lines.append(f"  satellite model={antennas_cfg.antenna_model}")
        else:
            lines.append("  Satellite-system antenna configuration is incomplete.")
        if antennas_cfg.antenna_model == _ANTENNA_MODEL_REC12 and antennas_cfg.rec12.z is not None:
            lines.append(
                "  Rec 1.2: "
                f"Gm={antennas_cfg.rec12.gm_dbi if antennas_cfg.rec12.gm_dbi is not None else np.nan:.2f} dBi, "
                f"LN={antennas_cfg.rec12.ln_db if antennas_cfg.rec12.ln_db is not None else np.nan:.2f} dB, "
                f"z={antennas_cfg.rec12.z:.3f}"
            )
        elif antennas_cfg.antenna_model == _ANTENNA_MODEL_REC14 and antennas_cfg.rec14.l is not None:
            lines.append(
                "  Rec 1.4: "
                f"Lt={antennas_cfg.rec14.lt_m if antennas_cfg.rec14.lt_m is not None else np.nan:.2f} m, "
                f"Lr={antennas_cfg.rec14.lr_m if antennas_cfg.rec14.lr_m is not None else np.nan:.2f} m, "
                f"l={int(antennas_cfg.rec14.l)}, "
                f"SLR={antennas_cfg.rec14.slr_db if antennas_cfg.rec14.slr_db is not None else np.nan:.2f} dB"
            )
            lines.append(
                "  far sidelobe: "
                f"start={antennas_cfg.rec14.far_sidelobe_start_deg if antennas_cfg.rec14.far_sidelobe_start_deg is not None else np.nan:.2f} deg, "
                f"level={antennas_cfg.rec14.far_sidelobe_level_dbi if antennas_cfg.rec14.far_sidelobe_level_dbi is not None else np.nan:.2f} dBi"
            )
        ras_antenna = antennas_cfg.ras
        if (
            ras_antenna.antenna_diameter_m is None
            and ras_antenna.operational_elevation_min_deg is None
            and ras_antenna.operational_elevation_max_deg is None
        ):
            lines.append("  RAS antenna: None configured.")
        else:
            lines.append(
                "  RAS antenna: "
                f"dish={ras_antenna.antenna_diameter_m if ras_antenna.antenna_diameter_m is not None else np.nan:.1f} m, "
                f"elev={ras_antenna.operational_elevation_min_deg if ras_antenna.operational_elevation_min_deg is not None else np.nan:.1f} .. "
                f"{ras_antenna.operational_elevation_max_deg if ras_antenna.operational_elevation_max_deg is not None else np.nan:.1f} deg"
            )
    lines.append("")
    ga = s0.grid_analysis
    lines.append("Grid / contours analyser:")
    lines.append(
        f"  indicative={ga.indicative_footprint_drop}, "
        f"spacing={ga.spacing_drop}, "
        f"leading={ga.leading_metric}, "
        f"rule={ga.cell_spacing_rule}"
    )
    if ga.cell_size_override_enabled:
        lines.append(
            "  cell size override="
            f"{ga.cell_size_override_km:.3f} km"
        )
    else:
        lines.append("  cell size override=off")
    lines.append("")
    lines.append("Service / demand:")
    _svc_is_uemr = _system_is_uemr(s0)
    if _has_valid_service_config(svc, uemr_mode=_svc_is_uemr):
        power_summary = _service_power_input_summary(
            _require_service_power_input(state), uemr_mode=_svc_is_uemr,
        )
        if _svc_is_uemr:
            lines.append(
                f"  UEMR mode (per-satellite bypass; no beam mechanics), "
                f"bandwidth={float(svc.bandwidth_mhz):.3f} MHz"
            )
            lines.append(f"  power input: {power_summary}")
        else:
            lines.append(
                f"  Nco={int(svc.nco)}, Nbeam={int(svc.nbeam)}, "
                f"selection={svc.selection_strategy}, "
                f"activity={float(svc.cell_activity_factor) * 100.0:.1f}%, "
                f"mode={_service_cell_activity_mode_label(str(svc.cell_activity_mode or _DEFAULT_SERVICE_CELL_ACTIVITY_MODE))}, "
                "seed="
                + (
                    "random"
                    if svc.cell_activity_seed_base is None
                    else str(int(svc.cell_activity_seed_base))
                )
            )
            lines.append(f"  power input: {power_summary}")
    else:
        lines.append("  Service inputs are incomplete.")
    lines.append("")
    lines.append("Run / outputs:")
    lines.append(
        f"  file={state.runtime.storage_filename}, rng={int(state.runtime.iteration_rng_seed)}, "
        f"families={_summarize_output_family_modes(state.runtime.output_families)}"
    )
    lines.append(
        f"  atmosphere={float(state.runtime.atmosphere_elev_min_deg):.2f} .. "
        f"{float(state.runtime.atmosphere_elev_max_deg):.2f} deg "
        f"(bin {float(state.runtime.atmosphere_elev_bin_deg):.2f}), "
        f"path={float(state.runtime.atmosphere_max_path_length_km):.1f} km, "
        f"target_alt={float(state.runtime.target_alt_km):.3f} km"
    )
    lines.append(
        f"  memory host={float(state.runtime.host_memory_budget_gb):.2f} GB, "
        f"gpu={float(state.runtime.gpu_memory_budget_gb):.2f} GB, "
        f"mode={state.runtime.memory_budget_mode}, "
        f"profile={state.runtime.memory_headroom_profile}, "
        f"target={state.runtime.scheduler_target_profile}, "
        f"terminal_cleanup={bool(state.runtime.terminal_gpu_cleanup)}"
    )
    lines.append("")
    hx = s0.hexgrid
    lines.append("Hexgrid:")
    lines.append(
        f"  geography={hx.geography_mask_mode}, coastline={hx.coastline_backend}, "
        f"RAS pointing={hx.ras_pointing_mode}, exclusion={hx.ras_exclusion_mode}"
    )
    return True, "\n".join(lines), constellation


def build_preview_frames(
    state: ScepterProjectState,
    parameters: PreviewParameters,
    *,
    cancel_callback: Callable[[], bool] | None = None,
) -> PreviewFrameSet:
    """
    Build cached geodetic preview frames for the viewer.

    Parameters
    ----------
    state : ScepterProjectState
        Current GUI state.
    parameters : PreviewParameters
        Session-only viewer time configuration.
    cancel_callback : callable, optional
        Best-effort cancellation hook evaluated at safe checkpoints. The
        preview builder does not guarantee interruption inside third-party
        propagation calls, but it will stop before or after major stages
        when cancellation has been requested.

    Returns
    -------
    PreviewFrameSet
        Cached preview frames. ``positions_ecef_km`` and
        ``positions_eci_km`` both have shape ``(F, S, 3)``.

    Raises
    ------
    ValueError
        Raised when the time controls are invalid.
    _PreviewBuildCancelledError
        Raised when ``cancel_callback`` reports cancellation.
    """
    def _raise_if_cancelled(stage: str) -> None:
        if cancel_callback is not None and bool(cancel_callback()):
            raise _PreviewBuildCancelledError(
                f"Preview build cancelled during {stage}."
            )

    start_utc = _to_utc_datetime(parameters.start_utc)
    end_utc = _to_utc_datetime(parameters.end_utc)
    frame_step_s = float(parameters.frame_step_s)
    if end_utc <= start_utc:
        raise ValueError("End UTC must be later than Start UTC.")
    if frame_step_s <= 0.0:
        raise ValueError("Frame step must be positive.")

    mjds, frame_times = _build_preview_mjds(start_utc, end_utc, frame_step_s)
    sample_times_s = np.asarray(
        [(stamp - frame_times[0]).total_seconds() for stamp in frame_times],
        dtype=np.float32,
    )
    earth_rotation_deg = _compute_earth_rotation_deg(frame_times)
    _raise_if_cancelled("preparing time samples")
    ras_position: np.ndarray | None = None
    ras_cfg = state.ras_station
    ras_incomplete = _has_any_ras_station_value(ras_cfg) and not _has_complete_ras_station_config(
        ras_cfg
    )
    if _has_complete_ras_station_config(ras_cfg):
        ras_position = _geodetic_to_cartesian_km(
            np.asarray([ras_cfg.longitude_deg], dtype=np.float64),
            np.asarray([ras_cfg.latitude_deg], dtype=np.float64),
            np.asarray([ras_cfg.elevation_m / 1000.0], dtype=np.float64),
        )[0]

    if len(state.active_system().belts) < 1 and (not state.systems or not any(s.belts for s in state.systems)):
        return PreviewFrameSet(
            times_utc=frame_times,
            sample_times_s=sample_times_s,
            positions_ecef_km=np.empty((len(frame_times), 0, 3), dtype=np.float32),
            positions_eci_km=np.empty((len(frame_times), 0, 3), dtype=np.float32),
            velocities_eci_km_s=np.empty((len(frame_times), 0, 3), dtype=np.float32),
            earth_rotation_deg=earth_rotation_deg,
            belt_names=[],
            belt_counts=np.empty(0, dtype=np.int64),
            belt_offsets=np.asarray([0], dtype=np.int64),
            belt_colors=[],
            ras_position_ecef_km=ras_position,
            status_note=(
                "Preview shows Earth only."
                if ras_position is None and not ras_incomplete
                else (
                    "Preview shows Earth only because the RAS station geometry is incomplete and no belts are defined."
                    if ras_incomplete
                    else "Preview shows Earth and RAS station only because no belts are defined."
                )
            ),
        )

    _raise_if_cancelled("building constellation metadata")
    try:
        constellation = build_constellation_from_state(
            state, all_systems=True, start_time=start_utc,
        )
    except Exception as exc:
        return PreviewFrameSet(
            times_utc=frame_times,
            sample_times_s=sample_times_s,
            positions_ecef_km=np.empty((len(frame_times), 0, 3), dtype=np.float32),
            positions_eci_km=np.empty((len(frame_times), 0, 3), dtype=np.float32),
            velocities_eci_km_s=np.empty((len(frame_times), 0, 3), dtype=np.float32),
            earth_rotation_deg=earth_rotation_deg,
            belt_names=[],
            belt_counts=np.empty(0, dtype=np.int64),
            belt_offsets=np.asarray([0], dtype=np.int64),
            belt_colors=[],
            ras_position_ecef_km=ras_position,
            status_note=(
                "Preview shows Earth only; "
                if ras_position is None and not ras_incomplete
                else (
                    "Preview shows Earth only because the RAS station geometry is incomplete; "
                    if ras_incomplete
                    else "Preview shows Earth and RAS station only; "
                )
            )
            + f"constellation is invalid: {exc}",
        )

    tle_list = np.asarray(constellation["tle_list"], dtype=object)
    belt_names = list(constellation["belt_names"])
    belt_counts = np.asarray(constellation["belt_sats"], dtype=np.int64)
    belt_offsets = np.concatenate(
        (
            np.asarray([0], dtype=np.int64),
            np.cumsum(belt_counts, dtype=np.int64),
        )
    )
    belt_colors = [_belt_color(idx) for idx in range(len(belt_names))]

    _raise_if_cancelled("propagating preview orbits")
    preview_result = cysgp4.propagate_many(
        mjds[:, np.newaxis, np.newaxis],
        tle_list[np.newaxis, np.newaxis, :],
        observers=None,
        do_eci_pos=True,
        do_eci_vel=True,
        do_geo=True,
        do_topo=False,
        do_obs_pos=False,
        do_sat_azel=False,
        do_sat_rotmat=False,
        sat_frame="zxy",
        on_error="raise",
        method="dwarner",
    )
    _raise_if_cancelled("collecting propagation outputs")
    geo = np.asarray(preview_result["geo"], dtype=np.float64)
    if geo.ndim == 4 and geo.shape[1] == 1:
        geo = geo[:, 0, :, :]
    if geo.ndim != 3 or geo.shape[-1] < 3:
        raise RuntimeError(f"Unexpected geodetic preview shape {geo.shape!r}.")
    eci = np.asarray(preview_result["eci_pos"], dtype=np.float64)
    if eci.ndim == 4 and eci.shape[1] == 1:
        eci = eci[:, 0, :, :]
    if eci.ndim != 3 or eci.shape[-1] < 3:
        raise RuntimeError(f"Unexpected inertial preview shape {eci.shape!r}.")
    eci_vel = np.asarray(preview_result["eci_vel"], dtype=np.float64)
    if eci_vel.ndim == 4 and eci_vel.shape[1] == 1:
        eci_vel = eci_vel[:, 0, :, :]
    if eci_vel.ndim != 3 or eci_vel.shape[-1] < 3:
        raise RuntimeError(f"Unexpected inertial velocity shape {eci_vel.shape!r}.")
    positions_ecef_km = _geodetic_to_cartesian_km(geo[..., 0], geo[..., 1], geo[..., 2])
    positions_eci_km = np.asarray(eci[..., :3], dtype=np.float32)
    velocities_eci_km_s = np.asarray(eci_vel[..., :3], dtype=np.float32)
    _raise_if_cancelled("assembling preview frames")
    status_note = (
        "RAS station is hidden because longitude, latitude, and elevation are incomplete."
        if ras_incomplete
        else ""
    )
    return PreviewFrameSet(
        times_utc=frame_times,
        sample_times_s=sample_times_s,
        positions_ecef_km=positions_ecef_km,
        positions_eci_km=positions_eci_km,
        velocities_eci_km_s=velocities_eci_km_s,
        earth_rotation_deg=earth_rotation_deg,
        belt_names=belt_names,
        belt_counts=belt_counts,
        belt_offsets=belt_offsets,
        belt_colors=belt_colors,
        ras_position_ecef_km=ras_position,
        status_note=status_note,
    )


class BeltTableModel(QtCore.QAbstractTableModel):
    """Editable Qt table model for GUI belt definitions."""

    # ``attr_name is None`` marks a synthetic column that reads from
    # the model's own state rather than a ``BeltConfig`` attribute —
    # currently just the "Show" visibility indicator at index 0.
    # Views that don't consume visibility state (the main-window
    # belt table) can simply ``hideColumn(0)``.
    _SHOW_COLUMN_INDEX: int = 0

    _columns: tuple[tuple[str, str | None, type[Any] | None], ...] = (
        ("Show", None, None),
        ("Name", "belt_name", str),
        ("S/P", "num_sats_per_plane", int),
        ("Planes", "plane_count", int),
        ("Alt [km]", "altitude_km", float),
        ("Ecc", "eccentricity", float),
        ("Inc [\u00b0]", "inclination_deg", float),
        ("ArgP [\u00b0]", "argp_deg", float),
        ("\u03a9 min [\u00b0]", "raan_min_deg", float),
        ("\u03a9 max [\u00b0]", "raan_max_deg", float),
        ("Min el [\u00b0]", "min_elevation_deg", float),
        ("Adj ofs", "adjacent_plane_offset", bool),
    )

    def __init__(
        self,
        belts: Sequence[BeltConfig] | None = None,
        parent: QtCore.QObject | None = None,
    ) -> None:
        super().__init__(parent)
        self._belts: list[BeltConfig] = list(belts) if belts is not None else []
        self._hidden_rows: set[int] = set()

    def set_hidden_rows(self, rows: Iterable[int]) -> None:
        """Mark rows whose belts are hidden in an associated 3D view.

        Each hidden row's "Show" column flips its eye glyph; the
        data columns themselves are unchanged. Callers drive this
        from their own visibility state (e.g. the wizard's
        ``_hidden_belts`` set).
        """
        new_hidden = {int(r) for r in rows if 0 <= int(r) < len(self._belts)}
        if new_hidden == self._hidden_rows:
            return
        affected = self._hidden_rows.symmetric_difference(new_hidden)
        self._hidden_rows = new_hidden
        for row in affected:
            idx = self.index(row, self._SHOW_COLUMN_INDEX)
            self.dataChanged.emit(
                idx,
                idx,
                [
                    QtCore.Qt.DisplayRole,
                    QtCore.Qt.ForegroundRole,
                    QtCore.Qt.ToolTipRole,
                ],
            )

    def rowCount(self, parent: QtCore.QModelIndex = QtCore.QModelIndex()) -> int:
        if parent.isValid():
            return 0
        return len(self._belts)

    def columnCount(self, parent: QtCore.QModelIndex = QtCore.QModelIndex()) -> int:
        if parent.isValid():
            return 0
        return len(self._columns)

    def headerData(
        self,
        section: int,
        orientation: QtCore.Qt.Orientation,
        role: int = QtCore.Qt.DisplayRole,
    ) -> Any:
        if orientation == QtCore.Qt.Horizontal and 0 <= section < len(self._columns):
            if role == QtCore.Qt.DisplayRole:
                return self._columns[section][0]
            if role == QtCore.Qt.ToolTipRole:
                return _BELT_COLUMN_HELP[section]
            return None
        if orientation == QtCore.Qt.Vertical:
            if role == QtCore.Qt.DisplayRole:
                return str(section + 1)
            return None
        return None

    _VALIDATION_RULES: dict[str, tuple[float | None, float | None, str]] = {
        "num_sats_per_plane": (1, None, "Must be \u2265 1"),
        "plane_count": (1, None, "Must be \u2265 1"),
        "altitude_km": (100, 100_000, "100\u2013100,000 km"),
        "eccentricity": (0.0, 0.99, "0 \u2264 e < 1"),
        "inclination_deg": (0, 180, "0\u2013180\u00b0"),
        "argp_deg": (0, 360, "0\u2013360\u00b0"),
        "raan_min_deg": (0, 360, "0\u2013360\u00b0"),
        "raan_max_deg": (0, 360, "0\u2013360\u00b0"),
        "min_elevation_deg": (0, 90, "0\u201390\u00b0"),
    }

    def _cell_error(self, belt: BeltConfig, attr_name: str) -> str | None:
        rule = self._VALIDATION_RULES.get(attr_name)
        if rule is None:
            return None
        lo, hi, msg = rule
        try:
            v = float(getattr(belt, attr_name))
        except (TypeError, ValueError):
            return msg
        if lo is not None and v < lo:
            return msg
        if hi is not None and v > hi:
            return msg
        if attr_name == "raan_max_deg":
            try:
                raan_min = float(belt.raan_min_deg)
                if v < raan_min:
                    return "\u03a9 max must be \u2265 \u03a9 min"
            except (TypeError, ValueError):
                pass
        return None

    # Glyphs used by the synthetic "Show" column — open eye when the
    # belt is visible in the 3D preview, a slashed eye when it's
    # hidden. ``U+1F441`` renders as a full-colour emoji on most
    # platforms; the slashed variant falls back to a circle-slash
    # overlay so it stays legible in monochrome fonts.
    _SHOW_GLYPH_VISIBLE: str = "\U0001F441"  # 👁
    _SHOW_GLYPH_HIDDEN: str = "\U0001F441\u20E0"  # 👁 with combining enclosing slash

    def data(self, index: QtCore.QModelIndex, role: int = QtCore.Qt.DisplayRole) -> Any:
        if not index.isValid():
            return None
        row = index.row()
        col = index.column()
        _, attr_name, attr_type = self._columns[col]

        if col == self._SHOW_COLUMN_INDEX:
            hidden = row in self._hidden_rows
            if role == QtCore.Qt.DisplayRole:
                return (
                    self._SHOW_GLYPH_HIDDEN if hidden else self._SHOW_GLYPH_VISIBLE
                )
            if role == QtCore.Qt.TextAlignmentRole:
                return int(QtCore.Qt.AlignCenter)
            if role == QtCore.Qt.ForegroundRole and hidden:
                return QtGui.QBrush(QtGui.QColor(160, 160, 160))
            if role == QtCore.Qt.ToolTipRole:
                return (
                    "Belt is hidden in the 3D view — click to show."
                    if hidden
                    else "Belt is visible in the 3D view — click to hide."
                )
            return None

        belt = self._belts[row]
        value = getattr(belt, attr_name)
        if attr_type is bool:
            if role == QtCore.Qt.CheckStateRole:
                return (
                    QtCore.Qt.CheckState.Checked
                    if value
                    else QtCore.Qt.CheckState.Unchecked
                )
            if role == QtCore.Qt.DisplayRole:
                return ""
            if role == QtCore.Qt.EditRole:
                return bool(value)
            return None
        if role in (QtCore.Qt.DisplayRole, QtCore.Qt.EditRole):
            return value
        if role == QtCore.Qt.BackgroundRole:
            err = self._cell_error(belt, attr_name)
            if err is not None:
                return QtGui.QColor(180, 40, 40, 100)
            return None
        if role == QtCore.Qt.ToolTipRole:
            err = self._cell_error(belt, attr_name)
            if err is not None:
                return err
            return None
        return None

    def flags(self, index: QtCore.QModelIndex) -> QtCore.Qt.ItemFlags:
        if not index.isValid():
            return QtCore.Qt.ItemIsEnabled
        col = index.column()
        if col == self._SHOW_COLUMN_INDEX:
            # The "Show" column reflects visibility state owned by the
            # wizard, not the ``BeltConfig`` — never editable, but stays
            # Selectable so keyboard navigation feels natural.
            return QtCore.Qt.ItemIsEnabled | QtCore.Qt.ItemIsSelectable
        base = (
            QtCore.Qt.ItemIsEnabled
            | QtCore.Qt.ItemIsSelectable
            | QtCore.Qt.ItemIsEditable
        )
        if self._columns[col][2] is bool:
            base |= QtCore.Qt.ItemIsUserCheckable
        return base

    def setData(
        self,
        index: QtCore.QModelIndex,
        value: Any,
        role: int = QtCore.Qt.EditRole,
    ) -> bool:
        if not index.isValid():
            return False
        if index.column() == self._SHOW_COLUMN_INDEX:
            # Visibility is owned by the wizard (not the belt config),
            # so any setData call aimed at this column is a no-op.
            return False
        belt = self._belts[index.row()]
        _, attr_name, attr_type = self._columns[index.column()]
        current = getattr(belt, attr_name)

        try:
            if attr_type is bool:
                if role == QtCore.Qt.CheckStateRole:
                    new_value = value == QtCore.Qt.CheckState.Checked
                elif role == QtCore.Qt.EditRole:
                    text = str(value).strip().lower()
                    new_value = text in {"1", "true", "yes", "y", "on"}
                else:
                    return False
            elif role == QtCore.Qt.EditRole:
                if attr_type is int:
                    new_value = int(float(value))
                elif attr_type is float:
                    new_value = float(value)
                else:
                    new_value = str(value).strip()
            else:
                return False
        except Exception:
            return False

        if attr_name == "belt_name":
            existing_names = [belt.belt_name for idx, belt in enumerate(self._belts) if idx != index.row()]
            new_value = _allocate_unique_belt_name(new_value, existing_names)

        if new_value == current:
            return False
        setattr(belt, attr_name, new_value)
        self.dataChanged.emit(
            index,
            index,
            [QtCore.Qt.DisplayRole, QtCore.Qt.EditRole, QtCore.Qt.CheckStateRole],
        )
        return True

    def belts(self) -> list[BeltConfig]:
        """Return a deep-copy-like snapshot of the edited belts."""
        return [BeltConfig.from_json_dict(belt.to_json_dict()) for belt in self._belts]

    def replace_belts(self, belts: Sequence[BeltConfig]) -> None:
        self.beginResetModel()
        self._belts = [
            BeltConfig.from_json_dict(belt.to_json_dict())
            for belt in belts
        ]
        self.endResetModel()

    def add_default_belt(self) -> None:
        row = len(self._belts)
        self.beginInsertRows(QtCore.QModelIndex(), row, row)
        default_belt = _default_belt_config()
        default_belt.belt_name = _allocate_unique_belt_name(
            "System3_Belt_1",
            [belt.belt_name for belt in self._belts],
        )
        self._belts.append(default_belt)
        self.endInsertRows()

    def duplicate_row(self, row: int) -> None:
        if not 0 <= row < len(self._belts):
            return
        duplicate = BeltConfig.from_json_dict(self._belts[row].to_json_dict())
        duplicate.belt_name = _allocate_unique_belt_name(
            duplicate.belt_name,
            [belt.belt_name for belt in self._belts],
        )
        insert_row = row + 1
        self.beginInsertRows(QtCore.QModelIndex(), insert_row, insert_row)
        self._belts.insert(insert_row, duplicate)
        self.endInsertRows()

    def remove_row(self, row: int) -> None:
        if not 0 <= row < len(self._belts):
            return
        self.beginRemoveRows(QtCore.QModelIndex(), row, row)
        del self._belts[row]
        self.endRemoveRows()

    def swap_rows(self, row_a: int, row_b: int) -> None:
        if not (0 <= row_a < len(self._belts) and 0 <= row_b < len(self._belts)):
            return
        self.layoutAboutToBeChanged.emit()
        self._belts[row_a], self._belts[row_b] = self._belts[row_b], self._belts[row_a]
        self.layoutChanged.emit()


class BooleanCheckboxDelegate(QtWidgets.QStyledItemDelegate):
    """Delegate that keeps boolean table cells checkbox-first and reliably toggleable."""

    def createEditor(
        self,
        parent: QtWidgets.QWidget,
        option: QtWidgets.QStyleOptionViewItem,
        index: QtCore.QModelIndex,
    ) -> QtWidgets.QWidget | None:
        del parent, option, index
        return None

    def editorEvent(
        self,
        event: QtCore.QEvent,
        model: QtCore.QAbstractItemModel,
        option: QtWidgets.QStyleOptionViewItem,
        index: QtCore.QModelIndex,
    ) -> bool:
        del option
        if not index.isValid():
            return False
        flags = model.flags(index)
        if not (flags & QtCore.Qt.ItemIsEnabled and flags & QtCore.Qt.ItemIsUserCheckable):
            return False
        if event.type() == QtCore.QEvent.MouseButtonRelease:
            current = model.data(index, QtCore.Qt.CheckStateRole)
            next_state = (
                QtCore.Qt.CheckState.Unchecked
                if current == QtCore.Qt.CheckState.Checked
                else QtCore.Qt.CheckState.Checked
            )
            return bool(model.setData(index, next_state, QtCore.Qt.CheckStateRole))
        if event.type() == QtCore.QEvent.KeyPress and isinstance(event, QtGui.QKeyEvent):
            if event.key() in (QtCore.Qt.Key_Space, QtCore.Qt.Key_Select):
                current = model.data(index, QtCore.Qt.CheckStateRole)
                next_state = (
                    QtCore.Qt.CheckState.Unchecked
                    if current == QtCore.Qt.CheckState.Checked
                    else QtCore.Qt.CheckState.Checked
                )
                return bool(model.setData(index, next_state, QtCore.Qt.CheckStateRole))
        return False


class PreviewBuildWorker(QtCore.QObject):
    """Background worker that builds preview frames off the GUI thread."""

    finished = QtCore.Signal(object, int, float)
    failed = QtCore.Signal(str, int)

    def __init__(
        self,
        state: ScepterProjectState,
        parameters: PreviewParameters,
        *,
        build_token: int,
        build_started: float,
    ) -> None:
        super().__init__()
        self._state = state
        self._parameters = parameters
        self._build_token = int(build_token)
        self._build_started = float(build_started)
        self._cancel_requested = False

    def cancel(self) -> None:
        """Request best-effort cancellation for the next safe checkpoint."""
        self._cancel_requested = True

    def _is_cancel_requested(self) -> bool:
        if self._cancel_requested:
            return True
        try:
            current_thread = QtCore.QThread.currentThread()
            if current_thread is not None and current_thread.isInterruptionRequested():
                return True
        except Exception:
            pass
        return False

    @QtCore.Slot()
    def _invoke_run(self) -> None:
        """Invoke ``run`` from the worker thread event loop."""
        self.run()

    @QtCore.Slot()
    def run(self) -> None:
        try:
            frame_set = build_preview_frames(
                self._state,
                self._parameters,
                cancel_callback=self._is_cancel_requested,
            )
        except _PreviewBuildCancelledError:
            self.failed.emit("Preview build cancelled.", self._build_token)
            return
        except Exception as exc:
            self.failed.emit(str(exc), self._build_token)
            return
        self.finished.emit(frame_set, self._build_token, self._build_started)


@dataclass(slots=True)
class HexgridPreviewComputation:
    """Pure-data result produced by the background hexgrid worker."""

    prepared_grid: dict[str, Any]
    boresight_ids: np.ndarray
    reuse_plan: dict[str, Any] | None
    preview_notes: list[str]
    effective_cell_km: float


class HexgridPreviewWorker(QtCore.QObject):
    """Background worker that prepares hexgrid preview inputs off the GUI thread."""

    finished = QtCore.Signal(object, int)
    failed = QtCore.Signal(str, int)

    def __init__(
        self,
        state: ScepterProjectState,
        *,
        effective_cell_km: float,
        build_token: int,
    ) -> None:
        super().__init__()
        self._state = state
        self._effective_cell_km = float(effective_cell_km)
        self._build_token = int(build_token)

    @QtCore.Slot()
    def _invoke_run(self) -> None:
        """Invoke ``run`` from the worker thread event loop."""
        self.run()

    @QtCore.Slot()
    def run(self) -> None:
        try:
            s0 = self._state.active_system()
            hx = s0.hexgrid
            constellation = build_constellation_from_state(self._state)
            prepared_grid = earthgrid.prepare_active_grid(
                point_spacing=self._effective_cell_km * u.km,
                altitudes=constellation["altitudes_q"],
                min_elevations=constellation["min_elevations_q"],
                inclinations=constellation["inclinations_q"],
                station_lat=float(self._state.ras_station.latitude_deg) * u.deg,
                station_lon=float(self._state.ras_station.longitude_deg) * u.deg,
                station_height=float(self._state.ras_station.elevation_m) * u.m,
                latitude_policy="any",
                geography_mask_mode=hx.geography_mask_mode,
                shoreline_buffer_km=hx.shoreline_buffer_km,
                coastline_backend=hx.coastline_backend,
                ras_exclusion_mode=hx.ras_exclusion_mode,
                ras_exclusion_layers=hx.ras_exclusion_layers,
                ras_exclusion_radius_km=hx.ras_exclusion_radius_km,
                ras_pointing_mode=hx.ras_pointing_mode,
            )

            preview_notes: list[str] = []
            boresight_ids = np.empty(0, dtype=np.int32)
            if hx.boresight_avoidance_enabled:
                try:
                    boresight_ids = earthgrid.resolve_theta2_active_cell_ids(
                        prepared_grid,
                        scope_mode=hx.boresight_theta2_scope_mode,
                        explicit_ids=_parse_theta2_cell_ids_text(
                            hx.boresight_theta2_cell_ids or ""
                        ),
                        layers=hx.boresight_theta2_layers,
                        radius_km=hx.boresight_theta2_radius_km,
                    )
                except Exception as exc:
                    preview_notes.append(f"Boresight scope warning: {exc}")
            reuse_plan = None
            try:
                reuse_plan = earthgrid.resolve_frequency_reuse_slots(
                    prepared_grid,
                    reuse_factor=int(s0.spectrum.reuse_factor),
                    anchor_slot=int(s0.spectrum.ras_anchor_reuse_slot),
                )
            except Exception as exc:
                preview_notes.append(f"Reuse plan warning: {exc}")
        except Exception as exc:
            self.failed.emit(str(exc), self._build_token)
            return

        self.finished.emit(
            HexgridPreviewComputation(
                prepared_grid=prepared_grid,
                boresight_ids=np.asarray(boresight_ids, dtype=np.int32),
                reuse_plan=reuse_plan,
                preview_notes=preview_notes,
                effective_cell_km=self._effective_cell_km,
            ),
            self._build_token,
        )


class _ProgressStreamProxy:
    def __init__(self, callback: Callable[[str], None]) -> None:
        self._callback = callback

    def write(self, text: str) -> int:
        text_use = "" if text is None else str(text)
        if text_use:
            self._callback(text_use)
        return len(text_use)

    def flush(self) -> None:
        return None

    def isatty(self) -> bool:
        return False


class RunCancelController:
    """Thread-safe cancellation controller shared between the GUI and run worker."""

    def __init__(self) -> None:
        self._lock = threading.Lock()
        self._mode = "none"

    def current_mode(self) -> str:
        with self._lock:
            return str(self._mode)

    def request(self, mode: str) -> str:
        mode_name = str(mode).strip().lower()
        with self._lock:
            current = str(self._mode)
            if current == "force":
                return current
            if mode_name == "force":
                self._mode = "force"
            elif current == "none":
                self._mode = "graceful"
            return str(self._mode)


class RunSimulationWorker(QtCore.QObject):
    """Background worker that executes a prepared GPU direct-EPFD run."""

    finished = QtCore.Signal(object)
    failed = QtCore.Signal(str)
    progress_text = QtCore.Signal(str)
    progress_value = QtCore.Signal(int, int)
    progress_event = QtCore.Signal(object)

    _ansi_escape_re = re.compile(r"\x1b\[[0-9;]*[A-Za-z]")
    _count_re = re.compile(r"(?P<current>\d+)\s*/\s*(?P<total>\d+)")

    def __init__(
        self,
        run_kwargs: Mapping[str, Any] | None = None,
        *,
        project_state: "ScepterProjectState | None" = None,
        prepare_callback: Callable[["ScepterProjectState"], Mapping[str, Any]] | None = None,
        cancel_controller: RunCancelController | None = None,
    ) -> None:
        super().__init__()
        self._run_kwargs = None if run_kwargs is None else dict(run_kwargs)
        self._progress_buffer = ""
        self._cancel_controller = cancel_controller or RunCancelController()
        self._project_state = project_state
        self._prepare_callback = prepare_callback

    def _handle_progress_chunk(self, text: str) -> None:
        if not text:
            return
        self._progress_buffer += str(text)
        parts = re.split(r"[\r\n]+", self._progress_buffer)
        trailing = parts.pop() if parts else ""
        for part in parts:
            self._handle_progress_line(part)
        if "\r" in text:
            if trailing.strip():
                self._handle_progress_line(trailing)
            self._progress_buffer = ""
        else:
            self._progress_buffer = trailing

    def _handle_progress_line(self, line: str) -> None:
        clean = self._ansi_escape_re.sub("", str(line)).strip()
        if not clean:
            return
        self.progress_text.emit(clean)
        match = self._count_re.search(clean)
        if match is not None:
            current = int(match.group("current"))
            total = int(match.group("total"))
            if total > 0:
                self.progress_value.emit(current, total)

    def _emit_progress_event(self, payload: Mapping[str, Any]) -> None:
        self.progress_event.emit(dict(payload))

    def _cancel_state(self) -> str:
        return self._cancel_controller.current_mode()

    def _set_cancel_mode(self, mode: str) -> None:
        emitted_mode = self._cancel_controller.request(mode)
        self.progress_event.emit(
            {
                "kind": "control",
                "phase": "stop_requested",
                "stop_mode": emitted_mode,
                "description": (
                    "Force stop requested. The run will stop at the next cancellation poll."
                    if emitted_mode == "force"
                    else "Graceful stop requested. The run will stop at the next safe boundary."
                ),
            }
        )

    @QtCore.Slot()
    def request_stop(self) -> None:
        self._set_cancel_mode("graceful")

    @QtCore.Slot()
    def request_force_stop(self) -> None:
        self._set_cancel_mode("force")

    @QtCore.Slot()
    def _invoke_run(self) -> None:
        """Invoke ``run`` from the worker thread event loop."""
        self.run()

    @QtCore.Slot()
    def run(self) -> None:
        stdout_prev = sys.stdout
        stderr_prev = sys.stderr
        proxy = _ProgressStreamProxy(self._handle_progress_chunk)
        sys.stdout = proxy
        sys.stderr = proxy
        try:
            if self._run_kwargs is None:
                if self._project_state is None or self._prepare_callback is None:
                    raise RuntimeError("Run worker requires either prepared kwargs or a project-state prepare callback.")
                self.progress_event.emit(
                    {
                        "kind": "prepare",
                        "phase": "prepare",
                        "prepare_index": 1,
                        "prepare_total": 2,
                        "description": "Building the simulation request and active grid in the worker thread...",
                    }
                )
                try:
                    run_kwargs = dict(self._prepare_callback(self._project_state))
                except Exception as exc:
                    self.failed.emit(f"Preflight failed: {exc}")
                    return
                cancel_mode = self._cancel_state()
                if cancel_mode in {"graceful", "force"}:
                    self.progress_event.emit(
                        {
                            "kind": "run_stopped",
                            "phase": "stopped",
                            "stop_mode": cancel_mode,
                            "description": "Run stopped before GPU execution started.",
                            "writer_stats_summary": {},
                        }
                    )
                    self.finished.emit({"run_state": "stopped"})
                    return
                self.progress_event.emit(
                    {
                        "kind": "prepare",
                        "phase": "prepare",
                        "prepare_index": 2,
                        "prepare_total": 2,
                        "description": "Preflight complete. Starting GPU execution...",
                    }
                )
            else:
                run_kwargs = dict(self._run_kwargs)
            run_kwargs["progress_callback"] = self._emit_progress_event
            run_kwargs["cancel_callback"] = self._cancel_state
            # Multi-system dispatch
            if run_kwargs.pop("_multi_system", False):
                system_run_kwargs = run_kwargs.pop("_system_run_kwargs", [])
                system_names = run_kwargs.pop("_system_names", [])
                output_system_groups = run_kwargs.pop("_output_system_groups", None)
                result = scenario.run_gpu_multi_system_epfd(
                    system_run_kwargs=system_run_kwargs,
                    shared_run_kwargs=run_kwargs,
                    system_names=system_names,
                    output_system_groups=output_system_groups,
                    progress_callback=self._emit_progress_event,
                    cancel_controller=self._cancel_controller,
                )
            else:
                result = scenario.run_gpu_direct_epfd(**run_kwargs)
        except Exception as exc:
            exc_name = type(exc).__name__
            # Provide actionable context for common GPU failures
            msg = str(exc)
            if "out of memory" in msg.lower() or "oom" in msg.lower():
                msg = f"GPU out of memory: {msg}\n\nTry reducing GPU memory budget, bulk timesteps, or output families."
            elif "cuda" in msg.lower():
                msg = f"CUDA error ({exc_name}): {msg}"
            else:
                msg = f"{exc_name}: {msg}"
            self.failed.emit(msg)
            return
        finally:
            sys.stdout = stdout_prev
            sys.stderr = stderr_prev
            if self._progress_buffer.strip():
                self._handle_progress_line(self._progress_buffer)
            self._progress_buffer = ""
        self.finished.emit(result)


def _keplerian_positions_eci_km(belts: list[BeltConfig]) -> list[np.ndarray]:
    """Compute satellite ECI positions at t=0 from Keplerian elements (no SGP4).

    Returns a list of (N, 3) arrays, one per belt.  Fast (~1ms for 10k sats).
    """
    R_EARTH_KM = 6378.137
    results: list[np.ndarray] = []
    for belt in belts:
        if belt.plane_count is None or belt.num_sats_per_plane is None:
            results.append(np.empty((0, 3), dtype=np.float32))
            continue
        alt = float(belt.altitude_km or 525.0)
        inc = np.radians(float(belt.inclination_deg or 53.0))
        ecc = float(belt.eccentricity or 0.0)
        argp = np.radians(float(belt.argp_deg or 0.0))
        raan_min = np.radians(float(belt.raan_min_deg or 0.0))
        raan_max = np.radians(float(belt.raan_max_deg or 360.0))
        n_planes = max(1, int(belt.plane_count))
        n_sats = max(1, int(belt.num_sats_per_plane))
        adj_offset = bool(belt.adjacent_plane_offset)
        a_km = R_EARTH_KM + alt
        raan_step = (raan_max - raan_min) / n_planes
        ma_step = 2.0 * np.pi / n_sats
        half_step = ma_step / 2.0
        total = n_planes * n_sats
        positions = np.empty((total, 3), dtype=np.float32)
        idx = 0
        cos_i, sin_i = np.cos(inc), np.sin(inc)
        for p in range(n_planes):
            raan = raan_min + p * raan_step
            cos_O, sin_O = np.cos(raan), np.sin(raan)
            ma_offset = half_step if (adj_offset and p % 2 == 1) else 0.0
            for s in range(n_sats):
                nu = s * ma_step + ma_offset  # true anomaly ≈ mean anomaly for small e
                r = a_km * (1.0 - ecc ** 2) / (1.0 + ecc * np.cos(nu))
                u = argp + nu  # argument of latitude
                cos_u, sin_u = np.cos(u), np.sin(u)
                # Perifocal → ECI rotation
                x = r * (cos_O * cos_u - sin_O * sin_u * cos_i)
                y = r * (sin_O * cos_u + cos_O * sin_u * cos_i)
                z = r * sin_u * sin_i
                positions[idx] = [x, y, z]
                idx += 1
        results.append(positions[:idx])
    return results


