class ConstellationWizardDialog(QtWidgets.QDialog):
    """Interactive constellation editor with embedded 3D viewer.

    The wizard delegates all 3D rendering, animation, skybox, and camera
    controls to :class:`ConstellationViewerWindow`, providing it with a
    ``state_provider`` that synthesises a :class:`ScepterProjectState`
    from the current belt table.  This eliminates duplicate rendering code
    and gives the wizard access to proper SGP4 propagation, starfield
    backgrounds, and satellite picking for free.
    """

    def __init__(
        self,
        belts: list[BeltConfig],
        parent: QtWidgets.QWidget | None = None,
    ) -> None:
        super().__init__(parent)
        self.setWindowTitle("Constellation Wizard")
        self.setWindowIcon(_load_app_icon())
        self.resize(1400, 860)
        self.setAttribute(QtCore.Qt.WA_DeleteOnClose, False)
        if parent is not None:
            self.setStyleSheet(parent.styleSheet())

        self._belts = [BeltConfig(**{f: getattr(b, f) for f in BeltConfig.__dataclass_fields__}) for b in belts]
        self._refresh_debounce = QtCore.QTimer(self)
        self._refresh_debounce.setSingleShot(True)
        self._refresh_debounce.setInterval(800)
        self._refresh_debounce.timeout.connect(self._refresh_viewer)

        # --- Layout: splitter with viewer (left) + belt editor (right) ---
        main_layout = QtWidgets.QHBoxLayout(self)
        main_layout.setContentsMargins(0, 0, 0, 0)
        main_layout.setSpacing(0)
        splitter = QtWidgets.QSplitter(QtCore.Qt.Horizontal, self)
        main_layout.addWidget(splitter)

        # Left: embedded ConstellationViewerWindow (compact mode)
        self._viewer: ConstellationViewerWindow | None = None
        self._viewer_host = QtWidgets.QStackedWidget(self)
        # Loading splash
        self._loading_label = QtWidgets.QLabel(
            "<br><br><br><h2>Building constellation preview\u2026</h2>"
            "<p>Forging TLEs and propagating orbits</p>",
            self,
        )
        self._loading_label.setAlignment(QtCore.Qt.AlignCenter)
        self._loading_label.setStyleSheet("color: #93c5fd; background: #0b1a2e;")
        self._viewer_host.addWidget(self._loading_label)
        try:
            viewer = ConstellationViewerWindow(
                state_provider=self._wizard_state,
                parent=self,
                auto_build=False,
                compact=True,
            )
            viewer.setWindowFlags(QtCore.Qt.Widget)
            viewer.setAttribute(QtCore.Qt.WA_DeleteOnClose, False)
            viewer.menuBar().setVisible(False)
            viewer.statusBar().setVisible(False)
            viewer.preview_build_completed.connect(self._on_viewer_ready)
            self._viewer_host.addWidget(viewer)
            self._viewer = viewer
            # Pre-size the preview span to match the wizard's default
            # playback speed (64x) so the very first build already
            # covers the animation window. Without this the viewer
            # would build once at the stock 1800 s span, fire
            # preview_build_completed, and then
            # ``_on_wizard_speed_changed`` would extend end_utc and
            # trigger an immediate second build — visible to the user
            # as a flash where satellites, orbit rings, and any
            # hidden-belt state disappear and reappear.
            default_speed = 64.0
            viewer_combo_idx = viewer.speed_combo.findData(default_speed)
            if viewer_combo_idx >= 0:
                viewer.speed_combo.setCurrentIndex(viewer_combo_idx)
            else:
                viewer._playback_multiplier = default_speed
            needed_sim_s = default_speed * self._MIN_REALTIME_PLAYBACK_S
            if viewer._preview_params.span_s < needed_sim_s:
                new_end = viewer._preview_params.start_utc + timedelta(
                    seconds=needed_sim_s
                )
                blocker = QtCore.QSignalBlocker(viewer.end_edit)
                viewer.end_edit.setDateTime(_utc_datetime_to_qdatetime(new_end))
                del blocker
                viewer._preview_params.end_utc = new_end
        except Exception:
            self._loading_label.setText("3D viewer unavailable")
        splitter.addWidget(self._viewer_host)

        # Right: Belt editor panel
        right_panel = QtWidgets.QWidget(self)
        right_layout = QtWidgets.QVBoxLayout(right_panel)
        right_layout.setContentsMargins(10, 10, 10, 10)
        right_layout.setSpacing(8)
        right_layout.addWidget(QtWidgets.QLabel("<b>Belt configuration</b>", self))
        # Preset combo
        preset_row = QtWidgets.QHBoxLayout()
        preset_row.addWidget(QtWidgets.QLabel("Preset:", self))
        self._preset_combo = QtWidgets.QComboBox(self)
        self._preset_combo.addItem("(custom)")
        for name in _WRC27_PRESETS:
            self._preset_combo.addItem(name)
        self._preset_combo.currentIndexChanged.connect(self._on_preset_selected)
        preset_row.addWidget(self._preset_combo, stretch=1)
        right_layout.addLayout(preset_row)
        # Belt table
        self._belt_model = BeltTableModel(self._belts, parent=self)
        self._belt_model.dataChanged.connect(self._on_belt_data_changed)
        self._belt_model.rowsInserted.connect(self._on_belt_structure_changed)
        self._belt_model.rowsRemoved.connect(self._on_belt_structure_changed)
        self._table = QtWidgets.QTableView(self)
        self._table.setModel(self._belt_model)
        self._table.setAlternatingRowColors(True)
        self._table.setSelectionBehavior(QtWidgets.QAbstractItemView.SelectRows)
        self._table.setSelectionMode(QtWidgets.QAbstractItemView.SingleSelection)
        header = self._table.horizontalHeader()
        header.setSectionResizeMode(QtWidgets.QHeaderView.ResizeToContents)
        header.setStretchLastSection(True)
        header.setMinimumSectionSize(40)
        self._table.verticalHeader().setVisible(False)
        checkbox_delegate = BooleanCheckboxDelegate(self._table)
        self._table.setItemDelegateForColumn(len(BeltTableModel._columns) - 1, checkbox_delegate)
        # Clicking the eye glyph in the "Show" column toggles the
        # belt's visibility in the 3D preview without going through
        # the Hide/Show-all buttons.
        self._table.clicked.connect(self._on_table_cell_clicked)
        # Larger font for the "Show" column so the eye emoji reads
        # cleanly at table row heights.
        self._table.setColumnWidth(BeltTableModel._SHOW_COLUMN_INDEX, 44)
        right_layout.addWidget(self._table, stretch=1)
        # Belt action buttons
        btn_row = QtWidgets.QHBoxLayout()
        add_btn = QtWidgets.QPushButton("+ Add", self)
        add_btn.clicked.connect(self._add_belt)
        remove_btn = QtWidgets.QPushButton("- Remove", self)
        remove_btn.clicked.connect(self._remove_belt)
        dup_btn = QtWidgets.QPushButton("Duplicate", self)
        dup_btn.clicked.connect(self._duplicate_belt)
        up_btn = QtWidgets.QPushButton("Up", self)
        up_btn.setToolTip("Move belt up")
        up_btn.clicked.connect(self._move_belt_up)
        down_btn = QtWidgets.QPushButton("Down", self)
        down_btn.setToolTip("Move belt down")
        down_btn.clicked.connect(self._move_belt_down)
        btn_row.addWidget(add_btn)
        btn_row.addWidget(remove_btn)
        btn_row.addWidget(dup_btn)
        btn_row.addWidget(up_btn)
        btn_row.addWidget(down_btn)
        btn_row.addStretch(1)
        right_layout.addLayout(btn_row)
        # Import / export
        io_row = QtWidgets.QHBoxLayout()
        import_btn = QtWidgets.QPushButton("Import JSON\u2026", self)
        import_btn.clicked.connect(self._import_belts)
        export_btn = QtWidgets.QPushButton("Export JSON\u2026", self)
        export_btn.clicked.connect(self._export_belts)
        io_row.addWidget(import_btn)
        io_row.addWidget(export_btn)
        io_row.addStretch(1)
        right_layout.addLayout(io_row)
        # Playback controls
        playback_row = QtWidgets.QHBoxLayout()
        self._play_btn = QtWidgets.QPushButton("\u25b6", self)
        self._play_btn.setMinimumWidth(48)
        self._play_btn.setSizePolicy(
            QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed
        )
        self._play_btn.setToolTip("Play / Stop animation")
        self._play_btn.clicked.connect(self._toggle_play)
        self._reset_btn = QtWidgets.QPushButton("\u23ee", self)
        self._reset_btn.setMinimumWidth(48)
        self._reset_btn.setSizePolicy(
            QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed
        )
        self._reset_btn.setToolTip("Reset to start")
        self._reset_btn.clicked.connect(self._reset_playback)
        self._speed_combo = QtWidgets.QComboBox(self)
        for value in (4.0, 16.0, 64.0, 256.0, 1024.0):
            self._speed_combo.addItem(f"{value:g}\u00d7", userData=float(value))
        self._speed_combo.setCurrentIndex(2)  # 64x default
        self._speed_combo.setSizePolicy(
            QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed
        )
        self._speed_combo.currentIndexChanged.connect(self._on_wizard_speed_changed)
        playback_row.addWidget(self._play_btn, stretch=1)
        playback_row.addWidget(self._reset_btn, stretch=1)
        playback_row.addWidget(self._speed_combo, stretch=1)
        # Belt visibility
        hide_btn = QtWidgets.QPushButton("Hide belt", self)
        hide_btn.setToolTip("Toggle selected belt visibility")
        hide_btn.setSizePolicy(
            QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed
        )
        hide_btn.clicked.connect(self._toggle_belt_visibility)
        self._hide_belt_btn = hide_btn
        self._table.selectionModel().selectionChanged.connect(
            lambda *_: self._refresh_hide_button_label()
        )
        show_all_btn = QtWidgets.QPushButton("Show all", self)
        show_all_btn.setSizePolicy(
            QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed
        )
        show_all_btn.clicked.connect(self._show_all_belts)
        playback_row.addWidget(hide_btn, stretch=2)
        playback_row.addWidget(show_all_btn, stretch=2)
        right_layout.addLayout(playback_row)
        # Summary
        self._summary_label = QtWidgets.QLabel("", self)
        self._summary_label.setWordWrap(True)
        self._summary_label.setStyleSheet("font-size: 11px;")
        right_layout.addWidget(self._summary_label)
        self._hidden_belts: set[int] = set()
        # Bottom buttons
        bottom_row = QtWidgets.QHBoxLayout()
        bottom_row.addStretch(1)
        apply_btn = QtWidgets.QPushButton("Apply to Project", self)
        apply_btn.setProperty("shellPrimaryAction", True)
        apply_btn.clicked.connect(self.accept)
        cancel_btn = QtWidgets.QPushButton("Cancel", self)
        cancel_btn.clicked.connect(self.reject)
        bottom_row.addWidget(apply_btn)
        bottom_row.addWidget(cancel_btn)
        right_layout.addLayout(bottom_row)
        splitter.addWidget(right_panel)
        splitter.setStretchFactor(0, 2)
        splitter.setStretchFactor(1, 1)

        self._update_summary()
        self._initial_build_pending = True
        self._playback_was_active = False

    def showEvent(self, event: QtGui.QShowEvent) -> None:
        super().showEvent(event)
        if self._initial_build_pending:
            self._initial_build_pending = False
            if self._viewer is not None:
                self._viewer_host.setCurrentWidget(self._viewer)
            QtCore.QTimer.singleShot(300, self._refresh_viewer)

    def changeEvent(self, event: QtCore.QEvent) -> None:
        super().changeEvent(event)
        if event.type() != QtCore.QEvent.ActivationChange or self._viewer is None:
            return
        if self.isActiveWindow():
            if self._playback_was_active and not self._viewer._timer.isActive():
                self._viewer.toggle_playback()
                self._play_btn.setText("\u25a0")
        else:
            if self._viewer._timer.isActive():
                self._playback_was_active = True
                self._viewer._timer.stop()
                self._play_btn.setText("\u25b6")
            else:
                self._playback_was_active = False

    # --- State provider for the embedded viewer ---
    def _wizard_state(self) -> ScepterProjectState:
        """Synthesise a minimal project state from the current belt table."""
        return ScepterProjectState(systems=[SatelliteSystemConfig(belts=list(self._belt_model.belts()))])

    def _refresh_viewer(self) -> None:
        if self._viewer is None:
            return
        # The viewer's VTK plotter needs a mapped (visible) widget to
        # initialise the OpenGL context.  Always show the viewer widget
        # before triggering a build; only show the loading label as an
        # overlay (via geometry).  A simpler alternative: just keep the
        # viewer visible at all times and let it show empty/old frames
        # while the background thread builds the new frame-set.
        self._viewer_host.setCurrentWidget(self._viewer)
        self._viewer.refresh_from_main_window()

    def _on_viewer_ready(self, *_args: object) -> None:
        if self._viewer is not None:
            self._viewer_host.setCurrentWidget(self._viewer)
            # Apply the wizard's speed setting and auto-start playback
            self._on_wizard_speed_changed()
            if not self._viewer._timer.isActive():
                self._viewer.toggle_playback()
                playing = self._viewer._timer.isActive()
                self._play_btn.setText("\u25a0" if playing else "\u25b6")
        # Every preview rebuild recreates the belt actors from scratch,
        # so the hidden-set the user has chosen must be re-applied here;
        # otherwise the freshly-built actors come up visible and the
        # table indicator would lie.
        if self._hidden_belts:
            self._apply_belt_visibility()

    # --- Playback controls ---
    def _toggle_play(self) -> None:
        if self._viewer is None:
            return
        self._viewer.toggle_playback()
        playing = self._viewer._timer.isActive()
        self._play_btn.setText("\u25a0" if playing else "\u25b6")

    def _reset_playback(self) -> None:
        if self._viewer is None:
            return
        self._viewer.reset_playback()
        self._play_btn.setText("\u25b6")

    _MIN_REALTIME_PLAYBACK_S = 120.0  # ensure at least 120s of wall-clock animation
    # 4× the original 30 s baseline so the default 64× build already
    # spans ~2 h of simulated time and switching to 256× / 1024×
    # speeds doesn't trip an immediate rebuild for a longer span.

    def _on_wizard_speed_changed(self, *_args: object) -> None:
        if self._viewer is None:
            return
        speed = float(self._speed_combo.currentData() or 64.0)
        idx = self._viewer.speed_combo.findData(speed)
        if idx >= 0:
            self._viewer.speed_combo.setCurrentIndex(idx)
        else:
            self._viewer._playback_multiplier = speed
        # Auto-extend the preview span so animation lasts at least 30 s
        # real-time. CRITICAL: ``apply_preview_settings`` re-reads end_utc
        # from the viewer's ``end_edit`` widget via
        # ``_current_preview_parameters()`` — so we MUST update the widget,
        # not the internal ``_preview_params``. Setting only the internal
        # value would be silently overwritten on the next apply call,
        # producing an infinite "build-rebuild" loop where every readiness
        # event re-extends the span and triggers another rebuild.
        needed_sim_s = speed * self._MIN_REALTIME_PLAYBACK_S
        current_span_s = self._viewer._preview_params.span_s
        if current_span_s < needed_sim_s:
            new_end = self._viewer._preview_params.start_utc + timedelta(seconds=needed_sim_s)
            # Update the widget so _current_preview_parameters() picks it up.
            blocker = QtCore.QSignalBlocker(self._viewer.end_edit)
            self._viewer.end_edit.setDateTime(_utc_datetime_to_qdatetime(new_end))
            del blocker
            self._viewer._preview_params.end_utc = new_end
            self._viewer.apply_preview_settings(force_frame_rebuild=True)

    # --- Belt visibility ---
    def _toggle_belt_visibility(self) -> None:
        rows = self._table.selectionModel().selectedRows()
        if not rows or self._viewer is None:
            return
        self._toggle_belt_row_visibility(int(rows[0].row()))

    def _on_table_cell_clicked(self, index: QtCore.QModelIndex) -> None:
        """Toggle belt visibility when the user clicks the "Show" column."""
        if not index.isValid() or self._viewer is None:
            return
        if index.column() != BeltTableModel._SHOW_COLUMN_INDEX:
            return
        self._toggle_belt_row_visibility(int(index.row()))

    def _toggle_belt_row_visibility(self, row: int) -> None:
        if self._viewer is None or row < 0 or row >= self._belt_model.rowCount():
            return
        if row in self._hidden_belts:
            self._hidden_belts.discard(row)
        else:
            self._hidden_belts.add(row)
        self._apply_belt_visibility()
        self._refresh_hide_button_label()

    def _show_all_belts(self) -> None:
        self._hidden_belts.clear()
        self._apply_belt_visibility()
        self._refresh_hide_button_label()

    def _refresh_hide_button_label(self) -> None:
        hide_btn = getattr(self, "_hide_belt_btn", None)
        if hide_btn is None:
            return
        rows = self._table.selectionModel().selectedRows()
        if rows and int(rows[0].row()) in self._hidden_belts:
            hide_btn.setText("Show belt")
        else:
            hide_btn.setText("Hide belt")

    def _apply_belt_visibility(self) -> None:
        # Reflect hidden state in the belt table (strikeout + muted text)
        # even when the 3D viewer is unavailable so the indicator still
        # tracks the user's intent.
        try:
            self._belt_model.set_hidden_rows(self._hidden_belts)
        except Exception:
            pass
        if self._viewer is None:
            return
        # Toggle satellite actors
        for i, bundle in enumerate(self._viewer._belt_render_bundles):
            try:
                bundle.actor.SetVisibility(i not in self._hidden_belts)
            except Exception:
                pass
        # Toggle orbit track actors by parsing belt index from name
        plotter_actors = getattr(self._viewer.plotter, "actors", {}) or {}
        for actor_name in self._viewer._orbit_track_actors:
            try:
                belt_idx = int(actor_name.replace(_ORBIT_TRACK_ACTOR_PREFIX, "").split("_")[0])
                actor = plotter_actors.get(actor_name)
                if actor is not None:
                    actor.SetVisibility(belt_idx not in self._hidden_belts)
            except Exception:
                pass
        try:
            self._viewer._safe_render()
        except Exception:
            pass
        self._update_summary()

    def result_belts(self) -> list[BeltConfig]:
        return list(self._belt_model.belts())

    def _add_belt(self) -> None:
        self._belt_model.add_default_belt()

    def _remove_belt(self) -> None:
        rows = self._table.selectionModel().selectedRows()
        if rows:
            self._belt_model.remove_row(int(rows[0].row()))

    def _duplicate_belt(self) -> None:
        rows = self._table.selectionModel().selectedRows()
        if not rows:
            return
        src = self._belt_model.belts()[int(rows[0].row())]
        existing_names = [b.belt_name for b in self._belt_model.belts()]
        unique_name = _allocate_unique_belt_name(f"{src.belt_name}_copy", existing_names)
        new_belt = BeltConfig(
            belt_name=unique_name,
            **{f: getattr(src, f) for f in BeltConfig.__dataclass_fields__ if f != "belt_name"},
        )
        current = list(self._belt_model.belts())
        current.append(new_belt)
        self._belt_model.replace_belts(current)

    def _move_belt_up(self) -> None:
        rows = self._table.selectionModel().selectedRows()
        if not rows:
            return
        row = int(rows[0].row())
        if row <= 0:
            return
        self._belt_model.swap_rows(row, row - 1)
        self._table.selectRow(row - 1)

    def _move_belt_down(self) -> None:
        rows = self._table.selectionModel().selectedRows()
        if not rows:
            return
        row = int(rows[0].row())
        if row >= self._belt_model.rowCount() - 1:
            return
        self._belt_model.swap_rows(row, row + 1)
        self._table.selectRow(row + 1)

    def _import_belts(self) -> None:
        path, _ = QtWidgets.QFileDialog.getOpenFileName(
            self, "Import belt definitions", "", "JSON files (*.json);;All files (*)",
        )
        if not path:
            return
        try:
            import json
            with open(path, "r", encoding="utf-8") as fh:
                payload = json.load(fh)
            belt_list = payload if isinstance(payload, list) else payload.get("belts", [])
            belts = [BeltConfig.from_json_dict(b) for b in belt_list]
            if not belts:
                QtWidgets.QMessageBox.warning(self, "Import", "No valid belts found in file.")
                return
            self._belt_model.replace_belts(belts)
            self._on_belt_data_changed()
        except Exception as exc:
            _show_exception_warning(self, "Import error", "Couldn't import belt definitions from the selected file.", exc)

    def _export_belts(self) -> None:
        path, _ = QtWidgets.QFileDialog.getSaveFileName(
            self, "Export belt definitions", "constellation.json",
            "JSON files (*.json);;All files (*)",
        )
        if not path:
            return
        try:
            import json
            belts = [b.to_json_dict() for b in self._belt_model.belts()]
            with open(path, "w", encoding="utf-8") as fh:
                json.dump({"belts": belts}, fh, indent=2)
        except Exception as exc:
            _show_exception_warning(self, "Export error", "Couldn't export belt definitions to the selected file.", exc)

    # --- Preset loading ---
    def _on_preset_selected(self, index: int) -> None:
        if index <= 0:
            return
        name = self._preset_combo.currentText()
        preset = _WRC27_PRESETS.get(name)
        if not preset:
            return
        belts = [BeltConfig.from_json_dict(b) for b in preset]
        self._belt_model.replace_belts(belts)
        self._on_belt_data_changed()

    @staticmethod
    def _is_visibility_only_data_change(args: tuple[object, ...]) -> bool:
        """Classify a ``BeltTableModel.dataChanged`` payload.

        Returns ``True`` when the signal reports a change confined to
        the synthetic "Show" column. The wizard uses this to skip
        the SGP4-propagation rebuild when all that flipped was the
        eye glyph — the preview is unaffected.
        """
        return (
            len(args) >= 2
            and isinstance(args[0], QtCore.QModelIndex)
            and isinstance(args[1], QtCore.QModelIndex)
            and args[0].isValid()
            and args[0].column() == BeltTableModel._SHOW_COLUMN_INDEX
            and args[1].column() == BeltTableModel._SHOW_COLUMN_INDEX
        )

    def _on_belt_data_changed(self, *args: object) -> None:
        """Route ``BeltTableModel.dataChanged`` to a rebuild or a no-op.

        Toggling the "Show" column only flips a display glyph — the
        satellite geometry is unchanged, so rebuilding the preview
        would be a waste. Earlier revisions treated every
        ``dataChanged`` as a reason to rebuild, which made the
        eye-click feel like editing a belt parameter; the 3D actors
        were already hidden/shown by ``_apply_belt_visibility`` in
        the caller path.
        """
        if self._is_visibility_only_data_change(args):
            return
        self._on_belt_structure_changed()

    def _on_belt_structure_changed(self, *_args: object) -> None:
        """Belt geometry / count changed — rebuild the preview."""
        n = self._belt_model.rowCount()
        self._hidden_belts = {i for i in self._hidden_belts if i < n}
        try:
            self._belt_model.set_hidden_rows(self._hidden_belts)
        except Exception:
            pass
        self._refresh_hide_button_label()
        self._update_summary()
        self._refresh_debounce.start()
        if self._preset_combo.currentIndex() != 0:
            self._preset_combo.blockSignals(True)
            self._preset_combo.setCurrentIndex(0)
            self._preset_combo.blockSignals(False)

    @staticmethod
    def _orbital_period_min(altitude_km: float, eccentricity: float = 0.0) -> float:
        R_EARTH_M = 6_378_137.0
        MU = 3.986004418e14
        r_perigee = R_EARTH_M + altitude_km * 1000.0
        a = r_perigee / (1.0 - eccentricity) if eccentricity < 1.0 else r_perigee
        return 2.0 * np.pi * np.sqrt(a ** 3 / MU) / 60.0

    @staticmethod
    def _walker_notation(belt: BeltConfig) -> str | None:
        """Return Walker delta string if belt looks like a Walker constellation."""
        spp = int(belt.num_sats_per_plane or 0)
        planes = int(belt.plane_count or 0)
        if spp < 1 or planes < 1:
            return None
        raan_min = float(belt.raan_min_deg or 0.0)
        raan_max = float(belt.raan_max_deg or 360.0)
        if abs(raan_max - raan_min - 360.0) > 1.0:
            return None
        total = spp * planes
        inc = float(belt.inclination_deg or 0.0)
        F = 1 if belt.adjacent_plane_offset else 0
        return f"{inc:.1f}\u00b0: {total}/{planes}/{F}"

    @staticmethod
    def _apogee_km(altitude_km: float, eccentricity: float) -> float:
        R_E = 6378.137
        r_perigee = R_E + altitude_km
        a = r_perigee / (1.0 - eccentricity) if eccentricity < 1.0 else r_perigee
        return a * (1.0 + eccentricity) - R_E

    def _update_summary(self) -> None:
        belts = self._belt_model.belts()
        lines: list[str] = []
        grand_total = 0
        for i, b in enumerate(belts):
            n_sats = int(b.num_sats_per_plane or 0) * int(b.plane_count or 0)
            grand_total += n_sats
            alt = float(b.altitude_km or 525.0)
            ecc = float(b.eccentricity or 0.0)
            period = self._orbital_period_min(alt, ecc)
            if period < 120:
                period_str = f"T={period:.1f} min"
            else:
                period_str = f"T={period / 60.0:.1f} h"
            if ecc > 0.01:
                apogee = self._apogee_km(alt, ecc)
                alt_str = f"{alt:,.0f}\u2013{apogee:,.0f} km"
            else:
                alt_str = f"{alt:,.0f} km"
            walker = self._walker_notation(b)
            walker_str = f" [{walker}]" if walker else ""
            color = _BELT_COLORS[i % len(_BELT_COLORS)]
            safe_name = _html_mod.escape(str(b.belt_name))
            lines.append(
                f'<span style="color:{color};">\u25cf</span> '
                f"<b>{safe_name}</b>: {n_sats:,} sats, {alt_str}, {period_str}{walker_str}"
            )
        header = f"{len(belts)} belt(s), {grand_total:,} satellites total"
        self._summary_label.setText(header + "<br>" + "<br>".join(lines))

    def closeEvent(self, event: QtGui.QCloseEvent) -> None:
        self._refresh_debounce.stop()
        if self._viewer is not None:
            try:
                self._viewer._is_closing = True
                self._viewer._timer.stop()
                self._viewer._rebuild_debounce_timer.stop()
            except Exception:
                pass
            try:
                self._viewer.close()
            except Exception:
                pass
            self._viewer = None
        super().closeEvent(event)
        _flush_deferred_deletions()


