        for target_index, page in enumerate(desired_page_order):
            tab_target = self._simulation_tab_container_for_page(page) if isinstance(page, QtWidgets.QWidget) else page
            current_index = self.tab_widget.indexOf(tab_target)
            if current_index >= 0 and current_index != target_index:
                self.tab_widget.tabBar().moveTab(current_index, target_index)
        for tab_i in range(self.tab_widget.count()):
            label = self.tab_widget.tabText(tab_i)
            title, detail = _SIMULATION_PAGE_COPY.get(label, (label, label))
            wrapper = self.tab_widget.widget(tab_i)
            if isinstance(wrapper, QtWidgets.QScrollArea):
                self._simulation_page_to_tab[label] = self._simulation_page_by_wrapper.get(wrapper, wrapper)
            else:
                self._simulation_page_to_tab[label] = wrapper
            item = QtWidgets.QListWidgetItem(title)
            item.setData(QtCore.Qt.UserRole, tab_i)
            item.setToolTip(detail)
            self.simulation_page_list.addItem(item)
        self._select_simulation_page(self.ras_tab)

