        self.save_as_button = QtWidgets.QPushButton("Save As", self._assistant_scroll_content)
        self.load_button = QtWidgets.QPushButton("Load", self._assistant_scroll_content)
        self.new_button = QtWidgets.QPushButton("New", self._assistant_scroll_content)
        self.open_result_button = QtWidgets.QPushButton("Postprocess", self._assistant_scroll_content)
        quick_buttons = (
            self.open_viewer_button,
            self.open_result_button,
            self.save_button,
            self.save_as_button,
            self.load_button,
            self.new_button,
        )
        for idx, button in enumerate(quick_buttons):
            button_grid.addWidget(button, idx // 2, idx % 2)
        self.open_result_button.setEnabled(False)
        assistant_layout.addWidget(action_group)
